    self:ModelNetMsgRecv(LProtoIds.HeroUpGradeResp, function(...)
        FireEvent(EventNames.ON_HERO_UP_GRADE)
    end)
    -- 请求升星返回
    self:ModelNetMsgRecv(LProtoIds.HeroUpStarResp, function(...)
        FireEvent(EventNames.ON_HERO_UP_STAR)
    end)
