    --end)
    -- 重生次数
    self:ModelNetMsgRecv(LProtoIds.HeroRebornInfoResp, function(...)
        self:OnHeroRebornInfoResp(...)
    end)
    -- 解锁
    self:ModelNetMsgRecv(LProtoIds.HeroLockResp, function(...)
        self:OnHeroLockResp(...)
    end)
