function ModelHero:InitStarRef()
    local HeroStarRefList = self._HeroStarRefList
    if not HeroStarRefList then
        HeroStarRefList = {}
        self._HeroStarRefList = HeroStarRefList
    end
    local recordHeroSkinMap = {}
    local heroUpStarNeedInfo = {}
    local heroUpStarRefIdByKey = {}
    for k, v in pairs(GameTable.CharacterStarRef) do
        local skinEffectId = v.skinEffectId
        if not string.isempty(skinEffectId) then
            local tempSkinMap = {}
            local skinEffectIdList = string.split(skinEffectId, "|")
            for idx, skinId in ipairs(skinEffectIdList) do
                local skinData = HeroStarRefList[k]
                if not skinData then
                    skinData = {}
                    HeroStarRefList[k] = skinData
                end
                local toNum = tonumber(skinId)
                skinData[toNum] = toNum
                if not tempSkinMap[toNum] then
                    tempSkinMap[toNum] = true
                end
            end
            recordHeroSkinMap[v.type] = tempSkinMap
        end
        local upStar = v.upStar
        if upStar == 1 then
            local heroType = v.type
            local heroData = heroUpStarNeedInfo[heroType]
            if not heroData then
                heroData = {}
                heroUpStarNeedInfo[heroType] = heroData
            end
            local star = v.star
            local heroStarDataInfo = heroData[star]
            if not heroStarDataInfo then
                heroStarDataInfo = {}
                heroData[star] = heroStarDataInfo
            end
            heroUpStarRefIdByKey[k] = { heroRefId = heroType, star = star }
            local tUpStarAppoint, tUpStarRange, tUpStarItem = {}, {}, {}
            local upStarAppoint, upStarRange, upStarItem = v.upStarAppoint, v.upStarRange, v.upStarItem
            local upStarAppointList = string.split(upStarAppoint, ",")
            for idx, val in ipairs(upStarAppointList) do
                val = string.split(val, "=")
                table.insert(tUpStarAppoint, { needRefId = tonumber(val[1]), needStar = tonumber(val[2]), needNum = tonumber(val[3]) })
            end
            local upStarRangeList = string.split(upStarRange, ",")
            for idx, val in ipairs(upStarRangeList) do
                val = string.split(val, "=")
                table.insert(tUpStarRange, { needRefId = tonumber(val[1]), needStar = tonumber(val[2]), needNum = tonumber(val[3]) })
            end
            local upStarItemList = string.split(upStarItem, ",")
            for idx, val in ipairs(upStarItemList) do
                val = string.split(val, "=")
                table.insert(tUpStarItem, { itemType = tonumber(val[1]), itemId = tonumber(val[2]), itemNum = tonumber(val[3]) })
            end
            heroStarDataInfo.upStarAppoint = tUpStarAppoint
            heroStarDataInfo.upStarRange = tUpStarRange
            heroStarDataInfo.upStarItem = tUpStarItem
            heroStarDataInfo.upStar = upStar
        end
    end
    self._heroUpStarNeedInfo = heroUpStarNeedInfo
    self._heroUpStarRefIdByKey = heroUpStarRefIdByKey
    self._recordHeroSkinMap = recordHeroSkinMap
end

function ModelHero:InitClassRef()
    local typeHeroClassRefList = {}
    local typeSortHeroClassRefList = {}
    local ref = GameTable.CharacterClassRef
    for k, v in pairs(ref) do
        local type = v.type
        local heroClassTypeList = typeHeroClassRefList[type]
        if not heroClassTypeList then
            heroClassTypeList = {}
            typeHeroClassRefList[type] = heroClassTypeList
        end
        heroClassTypeList[k] = v

        local typeSortHeroClassTypeList = typeSortHeroClassRefList[type]
        if not typeSortHeroClassTypeList then
            typeSortHeroClassTypeList = {}
            typeSortHeroClassRefList[type] = typeSortHeroClassTypeList
        end
        table.insert(typeSortHeroClassTypeList, v)
    end
    self._typeHeroClassRefList = typeHeroClassRefList

    for cType, refList in ipairs(typeSortHeroClassRefList) do
        table.sort(refList, function(a, b)
            return a.grade < b.grade
        end)
    end
    self._typeSortHeroClassRefList = typeSortHeroClassRefList
end

