function ModelHero:InitEffectRef()
    local HeroEffectRefList = self._HeroEffectRefList
    if not HeroEffectRefList then
        HeroEffectRefList = {}
        self._HeroEffectRefList = HeroEffectRefList
    end
    local heroDrawing2EffectIdMap = {}
    --处理多形态的数据  数据格式为 [originID]={id} sord by needStar
    local polymorphism = {}
    local originId = {}
    local originRefId, needStar,heroDrawing
    for k, v in pairs(GameTable.CharacterEffectRef) do
        local jumpItem = v.jumpItem
        if not string.isempty(jumpItem) then
            local jumpItemList = string.split(jumpItem, "|")
            for idx, itemRefId in ipairs(jumpItemList) do
                local itemData = HeroEffectRefList[k]
                if not itemData then
                    itemData = {}
                    HeroEffectRefList[k] = itemData
                end
                local toNum = tonumber(itemRefId)
                itemData[toNum] = toNum
            end
        end

        originRefId = v.originRefId
        needStar = v.needStar
        if originRefId and originRefId > 0 and needStar and needStar > 0 then
            local data = { refId = k, needStar = needStar }
            local tmpList = polymorphism[originRefId]
            if not tmpList then
                tmpList = {}
                polymorphism[originRefId] = tmpList
            end
            table.insert(tmpList, data)

            originId[k] = originRefId
        end


        heroDrawing = v.heroDrawing
        local heroDrawing2EffectIds = heroDrawing2EffectIdMap[heroDrawing]
        if not heroDrawing2EffectIds then
            heroDrawing2EffectIds = {}
            heroDrawing2EffectIdMap[heroDrawing] = heroDrawing2EffectIds
        end
        table.insert(heroDrawing2EffectIds,k)
    end

    for k, v in pairs(polymorphism) do
        table.sort(v, function(a, b)
            return a.needStar < b.needStar
        end)
    end
    self._polymorphism = polymorphism
    self._originId = originId
    self._heroDrawing2EffectIdMap = heroDrawing2EffectIdMap
end

function ModelHero:GetHeroDrawing2EffectIds(resName)
    return self._heroDrawing2EffectIdMap[resName]
end

function ModelHero:InitHeroRef()
    local recommendRuneHeroList = {}                -- 英雄ID对应的天赋技能列表
    local recommendRuneKeyToHeroList = {}            -- 天赋技能ID对应的英雄
    local initStarIdList = {}                       -- 初始化星级列表
    local initRaceHeroList = {}

    local initStar, raceType
    for heroRefId, v in pairs(GameTable.CharacterRef) do
        local recommendRune = string.split(v.recommendRune, ",")
        local len = #recommendRune
        if len > 0 then
            local recommendRuneHeroInfo = {}
            for idx, val in ipairs(recommendRune) do
                local runeKillRefId = tonumber(val)
                recommendRuneHeroList[runeKillRefId] = runeKillRefId

                local recommendRuneKeyInfo = recommendRuneKeyToHeroList[runeKillRefId]
                if not recommendRuneKeyInfo then
                    recommendRuneKeyInfo = {}
                    recommendRuneKeyToHeroList[runeKillRefId] = recommendRuneKeyInfo
                end
                recommendRuneKeyInfo[heroRefId] = heroRefId
            end
            recommendRuneHeroList[heroRefId] = recommendRuneHeroInfo
        end

        initStar = v.initStar
        local initStarList = initStarIdList[initStar]
        if not initStarList then
            initStarList = {}
            initStarIdList[initStar] = initStarList
        end
        table.insert(initStarList, heroRefId)

        raceType = v.raceType
        local initRaceList = initRaceHeroList[raceType]
        if not initRaceList then
            initRaceList = {}
            initRaceHeroList[raceType] = initRaceList
        end
        table.insert(initRaceList, {
            heroRefId = heroRefId,
            initStar = initStar,
        })

    end

    self._recommendRuneHeroList = recommendRuneHeroList
    self._recommendRuneKeyToHeroList = recommendRuneKeyToHeroList

    self._initStarIdList = initStarIdList
    self._initRaceHeroList = initRaceHeroList
end

