function ModelHero:InitHeroQualityList()
    self._qualityList = {}
    self._barrageColorList = {}
    local heroUpStarQuality = GameTable.CharacterConfigRef["heroUpStarQuality"]
    if not string.isempty(heroUpStarQuality) then
        local tempList = string.split(heroUpStarQuality, ",")
        for i, v in ipairs(tempList) do
            local tempData = string.split(v, "=")
            local tempStar, tempQuality = tonumber(tempData[1]), tonumber(tempData[2])
            self._qualityList[tempStar] = tempQuality
        end
    end
    local heroCommentColor = GameTable.CharacterConfigRef["heroCommentColor"]
    if not string.isempty(heroCommentColor) then
        local tempList = string.split(heroCommentColor, ",")
        for i, v in ipairs(tempList) do
            table.insert(self._barrageColorList, v)
        end
    end
end

