-- 材料
function ModelHero:GetHeroColorByStar(star, change)
    local maxQuality = 0
    for nStar, nQuality in pairs(self._qualityList) do
        if star >= nStar and maxQuality <= nQuality then
            maxQuality = nQuality
        end
    end
    if maxQuality ~= 0 then
        return gModelItem:GetColorByQualityId(maxQuality, change)
    end
end

function ModelHero:OnPowerShowResp(pb, ret)
    local needShowHeroPowerTips = self:GetNeedHeroPowerTips()

    local showType = pb.type
    local _powers = pb.powers
    for i, v in ipairs(_powers) do
        local key = v.key
        if showType == 2 then
            local heroStruct = self:GetHeroById(key)
            if heroStruct then
                local newPower = v.power
                if needShowHeroPowerTips and key == self._needShowPowerTipsHeroId then
                    needShowHeroPowerTips = true
                    local oldPower = heroStruct:GetPower()
                    self._heroTipPowerChangData = {
                        isReceived = true,
                        powerPre = oldPower,
                        subValue = newPower - oldPower,
                    }
                end

                heroStruct:SetPower(newPower)
            end
        end
    end

    if needShowHeroPowerTips then
        self:TryShowHeroPowerTips()
    end
end

