    if GF.FindFirstWndByName("UISkinBreakReward") then
        return
    end

    GF.OpenWnd("UISkinBreakReward",{
        consumeData = pb.consume,
        itemData = pb.items,
    })
end

function ModelHero:OnHeroFavorabilityInfoResp(pb)
    self._loveTotalLevel = pb.loveLevel
    self._loveTotalValue = pb.loveValue
    self._gardenShowHeroEffRefId = pb.effectId

    for k, v in ipairs(pb.infoList or {}) do
        local loveInfo = self.favorabilityInfo[v.heroRefId]
        if not loveInfo then
            loveInfo = StructFavorability:New()
            loveInfo:CreateByPb(v)
            self.favorabilityInfo[v.heroRefId] = loveInfo
        end
    end

    FireEvent(EventNames.FAVORABILITY_EXP_UPDATE)
end

function ModelHero:OnHeroFavorabilityUnlockResp(pb)
    local loveInfo = {}
    loveInfo = StructFavorability:New()
    loveInfo:CreateByPb(pb.HeroFavorabilityInfo)
    self.favorabilityInfo[pb.HeroFavorabilityInfo.heroRefId] = loveInfo
    FireEvent(EventNames.FAVORABILITY_UNLOCKACTION)
end

