-- 废弃接口
function ModelHero:OnHeroUpStarReqByHeroInfoWnd(id, appointedlist, rangelist, rangItemlist, isHeroInfoWnd)
    local pb = LProtoHelper.CreateProto(LProtoIds.HeroUpStarReq)
    pb.id = id
    if isHeroInfoWnd then
        for i, v in ipairs(appointedlist) do
            for k, _id in pairs(v) do
                table.insert(pb.appointeds, _id)
            end
        end
        for i, v in ipairs(rangelist) do
            for k, _id in pairs(v) do
                table.insert(pb.ranges, _id)
            end
        end
    else
        for k, v in pairs(appointedlist) do
            for _k, _v in pairs(v) do
                table.insert(pb.appointeds, _v)
            end
        end
        for k, v in pairs(rangelist) do
            for _k, _v in pairs(v) do
                table.insert(pb.ranges, _v)
            end
        end
    end
    local items = pb.items
    for k, v in pairs(rangItemlist) do
        for refId, num in pairs(v) do
            local itemInfo = items:add()
            itemInfo.refId = tonumber(refId)
            itemInfo.num = tonumber(num)
        end
    end
    SendMessage(pb, LProtoIds.HeroUpStarReq)
end

function ModelHero:OnHeroUpStarReq(upHeroList, upType)
    local pb = LProtoHelper.CreateProto(LProtoIds.HeroUpStarReq)
    local upStars = pb.upStars
    for idx, heroUpStarInfo in ipairs(upHeroList) do
        local upHeroInfo = upStars:add()
        upHeroInfo.id = heroUpStarInfo.id
        local appointedlist = heroUpStarInfo.appointedlist
        for k, v in pairs(appointedlist) do
            for _k, id in pairs(v) do
                table.insert(upHeroInfo.appointeds, id)
            end
        end
        local rangelist = heroUpStarInfo.rangelist
        for k, v in pairs(rangelist) do
            for _k, id in pairs(v) do
                table.insert(upHeroInfo.ranges, id)
            end
        end
        local items = upHeroInfo.items
        local itemsList = heroUpStarInfo.rangItemList
        for i, v in pairs(itemsList) do
            for refId, num in pairs(v) do
                local tNum = tonumber(num)
                if tNum > 0 then
                    local itemInfo = items:add()
                    itemInfo.refId = tonumber(refId)
                    itemInfo.num = tNum
                end
            end
        end
    end
    upType = upType or 0
    pb.type = upType
    SendMessage(pb, LProtoIds.HeroUpStarReq)
end

function ModelHero:OnHeroAttributeReq(id, playerId, type, serverId, open, other)
    local pb = LProtoHelper.CreateProto(LProtoIds.HeroAttributeReq)
    pb.id = id
    if not string.isempty(playerId) then
        pb.playerId = playerId
    end
    pb.type = type or 1
    if (serverId) then
        pb.serverId = serverId
    end
    if open then
        pb.open = open
    end
    if other then
        pb.other = tostring(other)
    end
    SendMessage(pb, LProtoIds.HeroAttributeReq)
end

function ModelHero:OnHeroAttributeResp(pb, ret)
    local id = pb.id
    local needShowHeroPowerTips = self:GetNeedHeroPowerTips()
    needShowHeroPowerTips = needShowHeroPowerTips and id == self._needShowPowerTipsHeroId
    local attrChangList = {}

    -- 装备属性
    local heroAttrList = self._heroAttrList
    if not heroAttrList then
        heroAttrList = {}
        self._heroAttrList = heroAttrList
    end
    local heroAttr = heroAttrList[id]
    if not heroAttr then
        heroAttr = {}
        heroAttrList[id] = heroAttr
    end
    local datas = pb.attrs
    for k, v in pairs(datas) do
        local refId = v.refId
        if refId then
            local value = v.value
            if needShowHeroPowerTips then
                local oldValue = heroAttr[refId]
                if oldValue then
                    local addNum = value - oldValue
                    if addNum > 0 then
                        local powerHero = self:GetAttrPowerHero(refId)
                        if powerHero > 0 then
                            local attrChangData = {
                                refId = refId,
                                addNum = addNum,
                            }
                            table.insert(attrChangList, attrChangData)
                        end
                    end
                end
            end

            heroAttr[refId] = value
        end
    end

    -- 装备穿戴
    -- local heroWearEquipList = self._heroWearEquipList
    -- if not heroWearEquipList then
    --     heroWearEquipList = {}
    --     self._heroWearEquipList = heroWearEquipList
    -- end
    -- local heroWear = heroWearEquipList[id]
    -- heroWear = {}
    -- heroWearEquipList[id] = heroWear
    -- local equipList = pb.equips
    -- for i = 1, #equipList do
    --     local data = equipList[i]
    --     local refId = data.refId
    --     local num = data.num
    --     heroWear[refId] = num
    -- end
    if not self._heroWearEquipList then
        self._heroWearEquipList = {}
    end
    self._heroWearEquipList[id] = {}
    for i = 1, #pb.equips do
        local refId = pb.equips[i].refId
        if not refId then
            refId = pb.equips[i]._refId
        end

        local cfg = gModelEquip:GetEquipRefByRefId(refId)
        if cfg then
            local type = cfg.type
            self._heroWearEquipList[id][type] = StructEquip:New()
            self._heroWearEquipList[id][type]:CreateByPb(pb.equips[i])
        end
    end

    -- 符文穿戴
    self._heroWearRuneList = self._heroWearRuneList or {}
    self._heroWearRuneList[id] = self:GetPbHeroRunes(pb.heroRunes)
    -- 符文穿戴(自身)
    self._ownWearRuneList = self._ownWearRuneList or {}
    if (pb.ownRunes) then
        self._ownWearRuneList[id] = self:GetPbHeroRunes(pb.ownRunes)
    end
    -- 天赋穿戴
    self._heroWearTalentList = self._heroWearTalentList or {}
    if (pb.talentSkills) then
        self._heroWearTalentList[id] = self:GetPbHeroTalentSkills(pb.talentSkills)
    end
    -- 天赋穿戴(自身)
    self._ownWearTalentList = self._ownWearTalentList or {}
    if (pb.ownTalentSkills) then
        self._ownWearTalentList[id] = self:GetPbHeroTalentSkills(pb.ownTalentSkills)
    end
    --宠物id
    -- local _ownPetIds = {}
    -- if pb.petIds then
    --     for index, value in ipairs(pb.petIds) do
    --         _ownPetIds[index] = value
    --     end
    -- end
    --寵物數據
    local _ownPetInfo = {}
    if pb.pets then
        for index, value in ipairs(pb.pets) do
            local pet = StructPet:New()
            pet:CreateByPb(value)
            _ownPetInfo[index] = pet
        end
    end
    --奇珍
    local _ownBadgeInfo = {}
    if pb.badgeWears then
        for _, value in ipairs(pb.badgeWears) do
            _ownBadgeInfo[value.slot] = value
        end
    end
    --魔偶（自身）
    self._ownGolemSuitList = {}
    local ownGolemSuit = pb.ownGolemSuit
    if ownGolemSuit and ownGolemSuit.golem and #ownGolemSuit.golem > 0 then
        local ownGolemSuitServerData
        for i, v in ipairs(ownGolemSuit.golem) do
            ownGolemSuitServerData = gModelGolem:GetGolemInfoFormPb(v)
            if ownGolemSuitServerData then
                table.insert(self._ownGolemSuitList, ownGolemSuitServerData)
            end
        end
    end
    self._golemSuitList = {}
    local golemSuit = pb.golemSuit
    if golemSuit and golemSuit.golem and #golemSuit.golem > 0 then
        local golemSuitServerData
        for i, v in ipairs(golemSuit.golem) do
            golemSuitServerData = gModelGolem:GetGolemInfoFormPb(v)
            if golemSuitServerData then
                table.insert(self._golemSuitList, golemSuitServerData)
            end
        end
    end
    --奎特牌（映射）
    local kSorceryCardInfo = pb.sorceryCardInfo
    local _kSorceryCardInfo = nil
    if kSorceryCardInfo then
        _kSorceryCardInfo = StructSorceryCardInfo:New()
        _kSorceryCardInfo:CreateByPb(kSorceryCardInfo)
        self._sorceryCardInfo = _kSorceryCardInfo
    end
    -- 新装备
    local heroOutfitList = self._heroOutfitList
    if not heroOutfitList then
        heroOutfitList = {}
        self._heroOutfitList = heroOutfitList
    end
    --屏蔽新装备
    --local heroOutfit = {}
    --heroOutfitList[id] = heroOutfit
    --local outfits = pb.outfits
    --for i, v in ipairs(outfits) do
    --	local position = v.position
    --	local outfit = v.outfit
    --	local outfitInfo = StructOutfit:New()
    --	outfitInfo:CreateByPb(outfit)
    --	heroOutfit[position] = outfitInfo
    --end
    -- 联盟技能
    local guildSkillList = self._guildSkillList
    if not guildSkillList then
        guildSkillList = {}
        self._guildSkillList = guildSkillList
    end
    local heroGuildSkill = {}
    guildSkillList[id] = heroGuildSkill
    local guildSkill = pb.guildSkill
    for i = 1, #guildSkill do
        local data = guildSkill[i]
        local position = data.position
        local skillId = data.skillId
        heroGuildSkill[position] = skillId
    end

    -- 觉醒
    --self:SaveHeroTreeInfo(playerId,id,pb.treeInfo)

    FireEvent(EventNames.HERO_ATTR_REQUEST_DONE, id)

    if pb.open == 1 then
        local sTreeInfo = nil
        if pb.treeInfo then
            sTreeInfo = StructHeroTreeInfo:New()
            sTreeInfo:CreateByPb(pb.treeInfo)
        end
        local sorceryCardInfo = pb.sorceryCardInfo
        local _sorceryCardInfo = nil
        if sorceryCardInfo then
            _sorceryCardInfo = StructSorceryCardInfo:New()
            _sorceryCardInfo:CreateByPb(sorceryCardInfo)
        end

        local serverGolemList = {}

        local golemSuit = pb.golemSuit
        local golemList = pb.golemList
        if golemSuit and golemSuit.golem and #golemSuit.golem > 0 then
            local golemServerData
            for i, v in ipairs(golemSuit.golem) do
                golemServerData = gModelGolem:GetGolemInfoFormPb(v)
                if golemServerData then
                    table.insert(serverGolemList, golemServerData)
                end
            end
        elseif golemList and #golemList > 0 then
            for i, v in ipairs(golemList) do
                table.insert(serverGolemList, v)
            end
        end
        -- 【G公共支持】删除伙伴晶石功能相关数据
        -- local crystalContent = pb.crystalContent
        self:OnReqShowHeroRet(id, sTreeInfo, nil, sorceryCardInfo, serverGolemList, nil, pb.name, _ownPetInfo,_ownBadgeInfo)
    end

    if needShowHeroPowerTips then
        self._heroTipAttrChangData = {
            isReceived = true,
            data = attrChangList,
        }
        self:TryShowHeroPowerTips()
    end
end

function ModelHero:GetPbHeroRunes(pbHeroRunes)
    local heroRune = {}
    local runeList = pbHeroRunes
    for i = 1, #runeList do
        local data = runeList[i]
        local position = data.position
        local runeInfo = StructRune:New()
        runeInfo:CreateByPb(data.runeInfo)
        heroRune[position] = runeInfo
    end
    return heroRune
end
function ModelHero:GetPbHeroTalentSkills(pbHeroTalentSkills)
