function ModelHero:OnHeroListResp(pb, ret)
    local heroList = {}
    self._heroList = heroList
    local heroIdList = {}
    -- self.refIdToId = {}
    local datas = pb.datas
    local data
    for i = 1, #datas do
        data = datas[i]
        local id = data.id
        local hero = heroList[id]
        if not hero then
            hero = StructHero:New()
            heroList[id] = hero
        end
        hero:CreateByPb(data)
        -- self.refIdToId[hero._refId] = hero._id
        heroIdList[id] = hero
    end
    self._heroNum = #datas
    if self._heroNum < 5 then
        self._isHeroListChange = true
    end
    local combatHeroList = gModelFormation:GetHeroFormationData(LCombatTypeConst.COMBAT_MAIN)
    for k, v in pairs(combatHeroList) do
        self:OnHeroAttributeReq(k)
    end

    self:SetAllHeroStarList()

    FireEvent(EventNames.On_Hero_Change, true)

    FireEvent(EventNames.ON_HERO_LIST_CHANGE)

    --self:CheckRuneNeedRuneHeroList(heroIdList)
    self:StarTryHeroTimer()
    if self:IsUseYouHua() then
        self:CheckHeroInfoList()
    end
end
