function ModelHero:CheckHeroInfoList()
    self:InitHeroInfoList()

    local heroStarList = self._heroStarList                -- 记录 				英雄star 	-> 英雄id
    local heroRefIdList = self._heroRefIdList            -- 记录 				英雄refId 	-> 英雄id
    local heroHistroyList = self._heroHistroyList        -- 历史记录英雄数据		英雄id		-> 英雄原始星级和refId

    local star, refId
    local heroList = self:GetHeroList()
    for k, v in pairs(heroList) do
        star = v:GetStar()
        refId = v:GetRefId()

        local starInfoList = heroStarList[star]
        if not starInfoList then
            starInfoList = {}
            heroStarList[star] = starInfoList
        end
        starInfoList[k] = v

        local refIdInfoList = heroRefIdList[refId]
        if not refIdInfoList then
            refIdInfoList = {}
            heroRefIdList[refId] = refIdInfoList
        end
        refIdInfoList[k] = v

        heroHistroyList[k] = {
            refId = refId,
            star = star,
        }
    end
end

