function ModelHero:OnHeroChangeResp(pb, ret)
    local heroList = self._heroList
    if not heroList then
        self._heroNum = 0
        heroList = {}
        self._heroList = heroList

    end
    local heroIdList = {}
    local delIdKeyList = {}                -- 删除的英雄id
    local changeKeyList = {}            -- 新增/变更英雄id
    local datas = pb.change
    for i = 1, #datas do
        local data = datas[i]
        local _type = data.syncType
        local heroData = data.hero
        local id = heroData.id
        local hero = heroList[id]
        if _type == 1 then
            if not hero then
                hero = StructHero:New()
                heroList[id] = hero
            end
            hero:CreateByPb(heroData)
            -- self.refIdToId[hero._refId] = hero._id
            heroIdList[id] = hero
            changeKeyList[id] = hero
        elseif _type == 2 then
            local idlist = data.ids
            for k, v in pairs(idlist) do
                id = v
                hero = heroList[id]
                if hero then
                    heroList[id] = nil
                    delIdKeyList[id] = id
                    -- self.refIdToId[hero._refId] = nil
                end
            end
        elseif _type == 3 then
            if delIdKeyList[id] then
                heroList[id] = nil
            else
                if not hero then
                    hero = StructHero:New()
                    heroList[id] = hero
                end
                hero:CreateByPb(heroData)
                heroIdList[id] = hero
                -- self.refIdToId[hero._refId] = hero._id
                changeKeyList[id] = hero
            end
        end
    end
    local heroNum = pb.heroNum
    if heroNum ~= 0 then
        self._heroNum = heroNum
        if heroNum > 5 then
            self._isHeroListRedChange = true
        end
    end

    if self:IsUseYouHua() then
        self:ReSetHeroInfoList(changeKeyList, delIdKeyList)
    end

    self:SetAllHeroStarList()
    FireEvent(EventNames.ON_HERO_LIST_CHANGE)

    --self:CheckRuneNeedRuneHeroList(heroIdList)
    self:StarTryHeroTimer()
end

function ModelHero:ReSetHeroInfoList(changeHeroList, removeHeroList)
    local heroStarList = self._heroStarList                -- 记录 				英雄star 	-> 英雄id
    local heroRefIdList = self._heroRefIdList            -- 记录 				英雄refId 	-> 英雄id
    local heroHistroyList = self._heroHistroyList        -- 历史记录英雄数据		英雄id		-> 英雄原始星级和refId

    local refId, star
    for id, t in pairs(removeHeroList) do
        local histroyHero = heroHistroyList[id]
        if histroyHero then
            refId = histroyHero.refId
            star = histroyHero.star

            local heroRefIdInfoList = heroRefIdList[refId]
            if heroRefIdInfoList then
                if heroRefIdInfoList[id] then
                    heroRefIdInfoList[id] = nil
                end
            end

            local heroStarInfoList = heroStarList[star]
            if heroStarInfoList then
                if heroStarInfoList[id] then
                    heroStarInfoList[id] = nil
                end
            end

        end
    end

    for id, changeInfo in pairs(changeHeroList) do
        refId = changeInfo:GetRefId()
        star = changeInfo:GetStar()

        local histroyHero = heroHistroyList[id]
        if histroyHero then
            --- 有历史记录的，证明是改变的数据，需要删除已经添加的数据

            local hHeroRefId = histroyHero.refId
            if hHeroRefId ~= refId then
                local refIdInfoList = heroRefIdList[hHeroRefId]
                if refIdInfoList then
                    refIdInfoList[id] = nil
                end
            end

            local tHeroStar = histroyHero.star
            if tHeroStar ~= star then
                local starInfoList = heroStarList[tHeroStar]
                if starInfoList then
                    starInfoList[id] = nil
                end
            end
        end

        local starInfoList = heroStarList[star]
        if not starInfoList then
            starInfoList = {}
            heroStarList[star] = starInfoList
        end
        starInfoList[id] = changeInfo

        local refIdInfoList = heroRefIdList[refId]
        if not refIdInfoList then
            refIdInfoList = {}
            heroRefIdList[refId] = refIdInfoList
        end
        refIdInfoList[id] = changeInfo

        heroHistroyList[id] = {
            refId = refId,
            star = star,
        }
    end
end

