function ModelHero:OnHeroMergeReq(id, appointedlist, rangelist, rangItemlist)
    local pb = LProtoHelper.CreateProto(LProtoIds.HeroMergeReq)
    pb.id = id
    for k, v in pairs(appointedlist) do
        for _k, _v in pairs(v) do
            table.insert(pb.appointeds, _v)
        end
    end
    for k, v in pairs(rangelist) do
        for _k, _v in pairs(v) do
            table.insert(pb.ranges, _v)
        end
    end
    local items = pb.items
    for k, v in pairs(rangItemlist) do
        for refId, num in pairs(v) do
            local itemInfo = items:add()
            itemInfo.refId = tonumber(refId)
            itemInfo.num = tonumber(num)
        end
    end
    SendMessage(pb, LProtoIds.HeroMergeReq)
end

