                        isResonance = serverData.isResonance,
                        grade = serverData.grade,
                        fightPower = serverData.fightPower,
                    }
                    table.insert(upHeroList, { itype = 2, heroData = heroData, num = 1 })
                    --table.insert(upHeroList,{itype = 2,heroId = v,num = 1})
                end
            end
        end
    end
    if isHaveUpHero then
        local data = { refId = 10009, func = func, closeFunc = closeFunc, leftFunc = closeFunc, itemList = upHeroList }
        gModelGeneral:OpenUIOrdinTips(data)
    else
        if func then
            func()
        end
    end
end

function ModelHero:CheckHeroConditon207(id)
    local curHeroStarRef = self:GetStarRefById(id)                -- 当前星级配置 当前角色
    local isEnought = false
    local showStr = ""
    if curHeroStarRef then
        local condition_ShowNeedHero = curHeroStarRef.upStar1

        if not string.isempty(condition_ShowNeedHero) then
            --不空在进行设置
            local condition_parse = string.split(condition_ShowNeedHero, ",")

            local count = tonumber(condition_parse[2])

            local condition_parse_1 = string.split(condition_parse[1], "=")

            local star = tonumber(condition_parse_1[3])

            --check 一下  不满足 就显示
            if not self:CheckHeroListIsEnoughtStarCount(self:GetHeroSortList(), star, count) then
                --如果没有满足  NeedStarHeroTips
                showStr = string.replace(ccClientText(10183), count, star)
                isEnought = false
            else
                isEnought = true
            end
        else
            isEnought = true
        end
    end

    return isEnought, showStr
end

