function ModelHero:OnHeroSkinListResp(pb, ret)
    local heroSkinList = self._heroSkinList
    if not heroSkinList then
        heroSkinList = {}
        self._heroSkinList = heroSkinList
    end
    local heroRefIdSkinList = self._heroRefIdSkinList
    if not heroRefIdSkinList then
        heroRefIdSkinList = {}
        self._heroRefIdSkinList = heroRefIdSkinList
    end
    local skins = pb.skins
    for i, v in ipairs(skins) do
        local skinRefId, hoerRefId = v.refId, v.hoerId
        heroSkinList[skinRefId] = {
            refId = skinRefId,
            endTime = v.endTime,
            heroId = v.id[1], ---穿戴英雄流水id
            starLevel = v.star,
            starRefId = v.starRefId
        }
        local heroRefIdData = heroRefIdSkinList[hoerRefId]
        if not heroRefIdData then
            heroRefIdData = {}
            heroRefIdSkinList[hoerRefId] = heroRefIdData
        end
        heroRefIdData[skinRefId] = {
            refId = skinRefId,
            endTime = v.endTime,
        }
    end

    FireEvent(EventNames.REFRESH_SKIN_INFO)

    self:StartSkinTimer()
end

