function ModelHero:StartSkinTimer()
    local timeType = ModelGeneral.REFRESHDATA_SKIN
    self:ClearAllTime(timeType)
    local heroSkinList = self._heroSkinList
    if not heroSkinList then
        heroSkinList = {}
        self._heroSkinList = heroSkinList
    end
    for k, v in pairs(heroSkinList) do
        local endTime = tonumber(v.endTime) / 1000
        if endTime ~= -1 and endTime > GetTimestamp() then
            self:CreateTimer(timeType, v.refId, endTime)
        end
    end
end

function ModelHero:StarTryHeroTimer()
    local timeType = ModelGeneral.REFRESHDATA_HERO
    self:ClearAllTime(timeType)
    local heroList = self._heroList
    for k, v in pairs(heroList) do
        if v:IsTryHero() then
            local endTime = v:GetEndTime()
            if endTime and endTime > GetTimestamp() then
                self:CreateTimer(timeType, v:GetId(), endTime)
            end
        end
    end
end

function ModelHero:CreateTimer(timeType, key, endTime)
    self:ClearTimer(timeType, key)
    local timerList = self._timerList[timeType]
    if not timerList then
        timerList = {}
        self._timerList[timeType] = timerList
    end

    local oldTime = timerList[key]
    if oldTime then
        LxTimer.LoopTimeStop(oldTime)
    end

    timerList[key] = LxTimer.LoopTimeCall(function()
        self:SetTimerCount(timeType, key, endTime)
    end, 1, false, -1)
end

function ModelHero:SetTimerCount(timeType, key, endTime)
    endTime = endTime - GetTimestamp()
    if endTime and endTime < 0 then
        self:ClearTimer(timeType, key, true)
    end
end

function ModelHero:ClearTimer(timeType, key, req)
    local timerList = self._timerList[timeType]
    if not timerList then
        return
    end

    local timer = timerList[key]
    if not timer then
        return
    end
    LxTimer.LoopTimeStop(timer)
    timerList[key] = nil

    if req then
        if timeType == ModelGeneral.REFRESHDATA_SKIN then
            gModelGeneral:OnRefreshDataReq(timeType, key)
        elseif timeType == ModelGeneral.REFRESHDATA_HERO then
            gModelGeneral:OnRefreshDataReq(timeType, 0, key)
        end
    end
end

function ModelHero:ClearAllTime(timeType)
    local timerList = self._timerList
    for k, v in pairs(timerList) do
        if not timeType or timeType == k then
            for p, q in pairs(v or {}) do
                self:ClearTimer(k, p)
            end
        end
    end

    if timeType then
        self._timerList[timeType] = {}
    else
        self._timerList = {}
    end
end
