function ModelHero:GetHeroTotalLove()
    local lv = 0
    local exp = 0
    for _, hero in pairs(self._heroList) do
        if hero and hero.loveLevel and hero.loveLevel > 0 then
            lv = lv + hero.loveLevel
        end
        if hero and hero.loveValue and hero.loveValue > 0 then
            exp = exp + hero.loveValue
        end
    end
    return lv, exp
end

function ModelHero:CheckIsIns(hero, info)
    info = info or {}
    local ignore = info.ignore
    local wearTalentRefId = info.wearTalentRefId
    local itemRefId = info.itemRefId
    local ins = false
    if not hero then
        return ins
    end
    --local id = hero:GetId()
    local runePosInfo = gModelRune:GetRunePosListByType(2)
    for idx, val in ipairs(runePosInfo) do
        if ins then
            break
        end
        local unlockType = val.unlockType
        local changeNum
        if unlockType == 1 then
            changeNum = hero:GetLv()
        elseif unlockType == 2 then
            changeNum = hero:GetStar()
        end
        if changeNum then
            ins = changeNum >= val.demand
        end
        if ins and not ignore then
            --[[			local heroAttr = self:GetHeroAttrAndEquipInfoById(id)
						ins = table.isempty(heroAttr)
						-- 有属性不需要请求，直接放回
						if not ins then break end]]

            -- 7.16 把天赋放在英雄结构里
            local talentSkills = hero:GetTalentSkills()
            ins = table.isempty(talentSkills)
            if not ins then
                break
            end
        elseif ins and ignore then
            --[[			local heroAttr,heroWearEquipList,heroWearRuneList,heroWearTalentList = self:GetHeroAttrAndEquipInfoById(id)
						ins = table.isempty(heroAttr)]]

            -- 7.16 把天赋放在英雄结构里
            local talentSkills = hero:GetTalentSkills()
            ins = table.isempty(talentSkills)
            -- 有属性不需要请求，直接放回
            if not ins and wearTalentRefId and itemRefId then
                local isWearSameSkill = false
                local runeSkillList = gModelRune:GetRuneUpItemInfoByItemRefId(itemRefId)
                for k, v in pairs(talentSkills) do
                    if isWearSameSkill then
                        break
                    end
                    isWearSameSkill = runeSkillList[v] and true or false
                end
                ins = isWearSameSkill
            end
        end
    end
    return ins
end

