function ModelHero:GetSameHeroRefIdList(refId, onlyGetHero, skillRefId, itemRefId)
    local list = {}
    if not onlyGetHero and ModelHero.IGNORE_RUNEHEROSHOW == 1 then
        return list
    end
    local heroList = self:GetHeroList()
    for i, v in pairs(heroList) do
        local ins = self:CheckIsIns(v, { ignore = true, wearTalentRefId = skillRefId, itemRefId = itemRefId })
        if ins then
            local heroRefId = v:GetRefId()
            if heroRefId == refId or refId == nil then
                table.insert(list, v)
            end
        end
    end
    return list
end
function ModelHero:GetNeedRuneListByRuneSkillRefId(heroRefId, skillRefId, itemRefId)
    local list = {}
    if ModelHero.IGNORE_RUNEHEROSHOW == 1 then
        return list
    end
    local runePosInfo = gModelRune:GetRunePosListByType(2)
    local runeLen = #runePosInfo
    local sameHeroRefIdList = self:GetSameHeroRefIdList(heroRefId, nil, skillRefId, itemRefId)
    for i, hero in ipairs(sameHeroRefIdList) do
        local talentSkills = hero:GetTalentSkills()
        if not table.isempty(talentSkills) then
            local isMoHaveMax = false
            local statusList = {}
            for pos, skillId in pairs(talentSkills) do
                local skillRef = gModelRune:GetSkillInfoByRefId(skillId)
                if skillRef then
                    local tNum = skillRef.nextId == -1 and 1 or 0
                    table.insert(statusList, tNum)
                end
            end
            local num = 0
            for idx, val in ipairs(statusList) do
                if val == 0 then
                    num = num + 1
                end
            end
            local statusNum = #statusList
            if num == runeLen then
                isMoHaveMax = true
            end
            if statusNum < runeLen then
                isMoHaveMax = true
            end
            if isMoHaveMax then
                local serverData = hero:GetServerData()
                table.insert(list, {
                    itype = LItemTypeConst.TYPE_HERO,
                    heroData = serverData
                })
            end
        end
    end
    return list
end

function ModelHero:GetMaxPowerHeroPower(race)
    local power = 0
    local list = self:GetHeroList()
    for i, v in pairs(list) do
        local heroRef = self:GetHeroRef(v._refId)
        if ((race == 0 or heroRef.raceType == race) and v._fightPower > power) then
            power = v._fightPower
        end
    end
    return power
end

