function ModelHero:GetHeroAttrAndEquipInfoById(id, showOwn)
    if not id then
        return {}, {}, {}, {}, {}
    end
    local inMapping = gModelResonance:CheckHeroInMappings(id)
    local otherMapping = gModelResonance:GetMappingOtherId(id)
    local beMapping = inMapping and otherMapping
    local heroWearRuneList, heroWearTalentList
    if (beMapping and showOwn) then
        heroWearRuneList = self._ownWearRuneList
        heroWearTalentList = self._ownWearTalentList
    else
        heroWearRuneList = self._heroWearRuneList
        heroWearTalentList = self._heroWearTalentList
    end
    local heroAttrList, heroWearEquipList, heroOutfitList, guildSkillList = self._heroAttrList, self._heroWearEquipList, self._heroOutfitList, self._guildSkillList
    if (not heroAttrList) and (not heroWearEquipList) and (not heroWearRuneList) and (not heroWearTalentList) and (not heroOutfitList) and (not guildSkillList) then
        return {}, {}, {}, {}, {}, {}
    else
        return heroAttrList[id], heroWearEquipList[id], heroWearRuneList[id], heroWearTalentList[id], heroOutfitList[id], guildSkillList[id]
    end
end
