function ModelHero:ClearCareerTypeAttrList(list)
    local heroAttrList = self._heroAttrList
    local heroList = self._heroList
    for k, v in pairs(heroList) do
        local refId = v:GetRefId()
        local ref = self:GetHeroRef(refId)
        if ref then
            local careerType = ref.careerType
            if list[careerType] and heroAttrList[k] then
                heroAttrList[k] = nil
            end
        end
    end
end

function ModelHero:GeneralClearCareerTypeAttrList(itype, list)
    local heroAttrList = self._heroAttrList
    local heroList = self._heroList
    for k, v in pairs(heroList) do
        if itype == 4 then
            if heroAttrList[k] then
                heroAttrList[k] = nil
            end
        else
            local refId = v:GetRefId()
            local ref = self:GetHeroRef(refId)
            if ref then
                local data
                if itype == 1 then
                    data = ref.raceType
                elseif itype == 2 then
                    data = ref.careerType
                elseif itype == 3 then
                    data = v:GetStar()
                end
                if data and list[data] and heroAttrList[k] then
                    heroAttrList[k] = nil
                end
            end
        end
    end
end

