function ModelHero:GetHeroRaceRefSortByRank()
    --通过rank 获取 race的排序 -- 同时插入一个rank 为0 的
    local list = {}

    local ref = GameTable.CharacterRaceRef

    table.insert(list, {
        refId = 0,
        icon = "public_race_0",
        rank = 0,
    })

    for k, v in pairs(ref) do
        table.insert(list, v)
    end

    table.sort(list, function(a, b)
        return a.rank < b.rank
    end)

    return list
end

