function ModelHero:PayBuyHeroTrench()
    local wndId = 10001
    local numBuy, vip = gModelVip:GetVipHeroBagNumBuy()
    local leftFunc
    if numBuy and vip then
        wndId = 10004
        leftFunc = function()
            local wndInst = GF.FindFirstWndByName("UIHuiYPay")
            if wndInst then
                FireEvent(EventNames.ON_VIPLEVEL_CHANGE, 2)
            else
                GF.OpenWndBottom("UIHuiYPay", { page = 2 })
                local callName = gModelCallHero:GetCallWndName()
                GF.CloseWndByName(callName)
                GF.CloseWndByName("UIYellSagaAward")
                -- GF.CloseWndByName("WndNewYearCall")
            end
        end
    end
    local buyNum = self:GetHeroBagExpNum()
    local nextBuyNum = buyNum + 1
    local heroBagNumList = self:GetHeroBagNumBuy()
    local str = heroBagNumList[nextBuyNum]
    if not str then
        GF.ShowMessage(ccClientText(10035))
        return
    end
    local strList = string.split(str, "=")
    local payNum, openNum = tonumber(strList[1]), tonumber(strList[2])
    local diamondRefId = 102001
    local func = function()
        local haveNum = gModelItem:GetNumByRefId(diamondRefId)
        if payNum > haveNum then
            gModelGeneral:OpenGetWayWnd({ itemId = diamondRefId })
        else
            self:OnHeroBagExpandReq(2)
        end
    end
    gModelGeneral:OpenUIOrdinTips({ refId = wndId, func = func, leftFunc = leftFunc,
                                      para = { payNum, openNum, vip, numBuy }, consume = payNum }, true)
end

