function ModelHero:GetPayItemNum(heroData, isInsertHero)
    local lv, grade, refId = heroData.lv, heroData.grade, heroData.refId
    local data = {}
    local needGold, needExp, needItem = 0, 0
    for k, v in pairs(GameTable.CharacterLevelRef) do
        if v.level < lv and v.needGold ~= -1 then
            needGold = needGold + v.needGold
            needExp = needExp + v.needExp
        end
    end
    local ref = self:GetHeroRef(refId)
    local classType = ref.classType
    for k, v in pairs(GameTable.CharacterClassRef) do
        if v.type == classType and v.grade < grade then
            local temp = v.needItem
            if not string.isempty(temp) then
                if not needItem then
                    needItem = temp
                else
                    needItem = needItem .. "," .. temp
                end
            end
        end
    end
    needItem = string.split(needItem, ",")
    local otherItemList = {}
    if grade ~= 0 then
        for i, v in ipairs(needItem) do
            v = string.split(v, "=")
            local itemRefId, itemNum = tonumber(v[2]), tonumber(v[3])
            if itemRefId == 101001 then
                needGold = needGold + itemNum
            elseif itemRefId == 104001 then
                needExp = needExp + itemNum
            else
                if not otherItemList[itemRefId] then
                    otherItemList[itemRefId] = 0
                end
                otherItemList[itemRefId] = otherItemList[itemRefId] + itemNum
            end
        end
    end
    if isInsertHero then
        table.insert(data, { refId = heroData.id, num = 1, itype = 2 })
    end
    if needGold > 0 then
        table.insert(data, { refId = 101001, num = needGold })
    end
    if needGold > 0 then
        table.insert(data, { refId = 104001, num = needExp })
    end
    for k, v in pairs(otherItemList) do
        if v > 0 then
            table.insert(data, { itype = 1, refId = k, num = v })
        end
    end
    return data
end

function ModelHero:GetPayItemNumByStarAndEndLv(heroId, starLv, endLv, downLv, downStar)
    local data = {}
    local needGold, needExp = 0, 0
    for k, v in pairs(GameTable.CharacterLevelRef) do
        local lv = v.level
        if starLv <= lv and endLv > lv then
            needGold = needGold + v.needGold
            needExp = needExp + v.needExp
        end
    end
    local runeList = gModelRune:GetRuneUpItemList(heroId, downLv, downStar)
    for k, v in pairs(runeList) do
        local refId, num = v.refId, v.num
        if refId == 101001 then
            needGold = needGold + num
        elseif refId == 104001 then
            needGold = needGold + num
        else
            table.insert(data, { itype = v.itype, refId = refId, num = num, id = v.id })
        end
    end
    if needGold > 0 then
        table.insert(data, { refId = 101001, num = needGold })
    end
    if needExp > 0 then
        table.insert(data, { refId = 104001, num = needExp })
    end
    return data
end

function ModelHero:GetUpNumLvPayItem(id, starlv, classId, grade, maxLv, notFiveLimit)
    local haveGold, haveExp = gModelItem:GetNumByRefId(101001), gModelItem:GetNumByRefId(104001)
    local data = {}
    local needGold, needExp = 0, 0
    local maxAddLv = maxLv or 5
    local addLv = 1
    local startLv = starlv
    local classRef = gModelHero:GetHeroClassById(classId)    -- 阶级表
    local needLv = classRef.needLevel                -- 升到下一阶的等级需求
    local classGrade = classRef.grade
    for i = 1, maxAddLv do
        local curLv = startLv + i - 1
        if needLv > curLv and classGrade == grade then
            local levelRef = gModelHero:GetHeroLevelById(curLv)
            local curneedGold, curneedExp = levelRef.needGold, levelRef.needExp
            if curneedGold == -1 and curneedGold == -1 then
                break
            else
                local tempGold, tempExp = needGold + curneedGold, needExp + curneedExp
                if tempGold > haveGold then
                    break
                end
                if tempExp > haveExp then
                    break
                end
                needGold = tempGold
                needExp = tempExp
                addLv = i
            end
        else
            if needLv ~= -1 then
                if needLv == curLv then
                    break
                end
                local levelRef = gModelHero:GetHeroLevelById(curLv)
                local curneedGold, curneedExp = levelRef.needGold, levelRef.needExp
                local tempGold, tempExp = needGold + curneedGold, needExp + curneedExp
                if tempGold > haveGold then
                    break
                end
                if tempExp > haveExp then
                    break
                end
                needGold = tempGold
                needExp = tempExp
                addLv = i
            else
                -- > 100级

                local heroStarRef = self:GetStarRefById(id) --gModelHero:GetHeroStarById(starId)
                local maxLevel = heroStarRef.maxLevel
                local lastLv = maxLevel - starlv

                if maxLv and maxLv >= 100 then
                    lastLv = maxLv - starlv
                end

                if lastLv > 5 and (not notFiveLimit) then
                    lastLv = 5
                end
                addLv = 1
                for starlevel = 1, lastLv do
                    local level = startLv + starlevel - 1
                    local levelRef = gModelHero:GetHeroLevelById(level)
                    local curneedGold, curneedExp = levelRef.needGold, levelRef.needExp
                    if curneedGold == -1 and curneedGold == -1 then
                        break
                    else
                        local tempGold, tempExp = needGold + curneedGold, needExp + curneedExp
                        if tempGold > haveGold then
                            break
                        end
                        if tempExp > haveExp then
                            break
                        end
                        needGold = tempGold
                        needExp = tempExp
                        addLv = starlevel
                    end
                end
                break
            end
        end
    end
    if needGold == 0 and needGold == 0 then
        local levelRef = gModelHero:GetHeroLevelById(starlv)
        needGold, needExp = levelRef.needGold, levelRef.needExp
    end
    return needGold, needExp, addLv
end

