function ModelHero:GetMonsterPbNameByRefId(refId, isRight)
    local ref = self:GetMonsterAttrByRefId(refId)
    local prefabName = nil
    local scale = nil
    local needFlip = false
    if not ref then
        printErrorN(string.format("not monsterAttrRef %s", refId))
        return
    end
    scale = ref.scale
    local effectid = ref.effectId
    local effRef = self:GetShowEffectById(effectid)
    if effRef then
        if isRight and not string.isempty(effRef.prefabNameRight) then
            prefabName = effRef.prefabNameRight
        else
            prefabName = effRef.prefabName
            needFlip = true
        end
    end

    return prefabName, scale, needFlip
end

