function ModelHero:GetHeroSortList(record, reversed, otherSort, powerSort)
    --获取有排序的英雄列表
    local heroList = self:GetHeroList()
    if not heroList then
        return {}
    end
    local sortHeroList = {}
    for k, v in pairs(heroList) do
        table.insert(sortHeroList, v)
    end

    if powerSort then
        table.sort(sortHeroList, function(hero1, hero2)
            local power1, power2 = hero1:GetPower(), hero2:GetPower()
            return power1 > power2
        end)
        return sortHeroList
    end

    local sortFun = nil
    if reversed then
        sortFun = self:GetReverseHeroSortComp(record)
    else
        sortFun = self:GetHeroSortComp(record, otherSort)
    end
    table.sort(sortHeroList, sortFun)
    return sortHeroList
end

function ModelHero:GetLimitRaceHeroList(info)
    local heroList = self:GetHeroList()
    if not heroList then
        return {}
    end

    local curRaceType = info.curRaceType
    local raceKeyList = info.raceKeyList
    local record = info.record
    local reversed = info.reversed
    local otherSort = info.otherSort
    local isShowTryHero = info.isShowTryHero or false
    local combatType = info.combatType
    local curCareerType = info.careerType or 0
    local showCombatSpiritHeroStatus = gModelFormation:CheckCombatShowSpiritHero(combatType)
    local raceList = {}
    if raceKeyList then
        for k, v in pairs(raceKeyList) do
            table.insert(raceList, v)
        end
    end
    if #raceList < 1 then
        --- 没有种族限制
        raceKeyList = nil
    end

    local isShowAll = curRaceType == UIHeroRaceList.ALL_RACE_REFID
    local sortHeroList = {}
    local heroRefId
    for k, v in pairs(heroList) do
        heroRefId = v:GetRefId()
        local isIns = false
        local raceType = self:GetHeroRace(heroRefId)
        local careerType = self:GetHeroCareerType(heroRefId)
        local bAdd_1 = curCareerType == 0 or careerType == curCareerType
        local bAdd_2 = curRaceType == 0 or raceType == curRaceType

        if bAdd_1 and bAdd_2 then
            if raceKeyList then
                if showCombatSpiritHeroStatus then
                    --- 显示被链接的星灵英雄
                    if gModelSpiritHero:IsSpiritHeroRaceType(raceType) then
                        local linkRace = gModelSpiritHero:GetSpiritLinkHeroRace(v:GetId())
                        if linkRace and raceKeyList[linkRace] then
                            if isShowTryHero or not v:IsTryHero() then
                                isIns = true
                            end
                        end
                    else
                        --- 非星灵英雄
                        if raceKeyList[raceType] then
                            if isShowTryHero or not v:IsTryHero() then
                                isIns = true
                            end
                        end
                    end
                else
                    if raceKeyList[raceType] then
                        if isShowTryHero or not v:IsTryHero() then
                            isIns = true
                        end
                    end
                end
            else
                --- 无种族限制
                if isShowTryHero or not v:IsTryHero() then
                    isIns = true
                end
            end
        end
        if isIns then
            table.insert(sortHeroList, v)
        end
    end

    local sortFun = nil
    if reversed then
        sortFun = self:GetReverseHeroSortComp(record)
    else
        sortFun = self:GetHeroSortComp(record, otherSort)
    end
    if gModelTower:IsTowerCombat(combatType) then
        sortFun = self:GetTowerHeroSort()
    end
    table.sort(sortHeroList, sortFun)
    return sortHeroList
end

function ModelHero:GetHeroSortComp(record, otherSort)
    local rec = record or {}
    local comp = function(hero1, hero2)
        local star1, star2 = hero1:GetStar(), hero2:GetStar()
        local lv1, lv2 = hero1:GetLv(), hero2:GetLv()
        local power1, power2 = hero1:GetPower(), hero2:GetPower()
        local refId1, refId2 = hero1:GetRefId(), hero2:GetRefId()
        local id1, id2 = hero1:GetId(), hero2:GetId()

        local isOneOn = rec[id1] and 1 or 2
        local isTwoOn = rec[id2] and 1 or 2
        if isOneOn ~= isTwoOn then
            return isOneOn < isTwoOn
        end

        if star1 ~= star2 then
            return star1 > star2
        end
        if lv1 ~= lv2 then
            return lv1 > lv2
        end
        if power1 ~= power2 then
            return power1 > power2
        end
        if refId1 ~= refId2 then
            return refId1 < refId2
        end
        return id1 > id2
    end
    local comp1 = function(hero1, hero2)
        local star1, star2 = hero1:GetStar(), hero2:GetStar()
        local lv1, lv2 = hero1:GetLv(), hero2:GetLv()
        local power1, power2 = hero1:GetPower(), hero2:GetPower()
        local refId1, refId2 = hero1:GetRefId(), hero2:GetRefId()
        local id1, id2 = hero1:GetId(), hero2:GetId()

        local quality1, quality2 = self:GetHeroInitQualityByRefId(refId1), self:GetHeroInitQualityByRefId(refId2)
        if quality1 ~= quality2 then
            return quality1 > quality2
        end

        local isOneOn = rec[id1] and 1 or 2
        local isTwoOn = rec[id2] and 1 or 2
        if isOneOn ~= isTwoOn then
            return isOneOn < isTwoOn
        end

        if star1 ~= star2 then
            return star1 > star2
        end
        if lv1 ~= lv2 then
            return lv1 > lv2
        end

        local race1, race2 = self:GetHeroType(refId1), self:GetHeroType(refId2)
        if race1 ~= race2 then
            --return race1 < race2
            --种族比较 使用新的比较
            local rank1 = gModelHero:GetHeroRaceRefRank(race1)
            local rank2 = gModelHero:GetHeroRaceRefRank(race2)
            return rank1 < rank2
        end
        if refId1 ~= refId2 then
            return refId1 > refId2
        end
        return id1 > id2
    end
    local func = otherSort and comp1 or comp
    return func
end
function ModelHero:GetTowerHeroSort()
    local func = function(hero1, hero2)
        local star1, star2 = hero1:GetStar(), hero2:GetStar()
        local lv1, lv2 = hero1:GetLv(), hero2:GetLv()
        local power1, power2 = hero1:GetPower(), hero2:GetPower()
        local refId1, refId2 = hero1:GetRefId(), hero2:GetRefId()
        local id1, id2 = hero1:GetId(), hero2:GetId()

        if power1 ~= power2 then
            return power1 > power2
        end
        if star1 ~= star2 then
            return star1 > star2
        end
        if lv1 ~= lv2 then
            return lv1 > lv2
        end
        if refId1 ~= refId2 then
            return refId1 < refId2
        end
        return id1 > id2
    end
    return func
end

function ModelHero:GetPowerSortHeroList()
    local heroList = self:GetHeroList()
    if not heroList then
        return {}
    end
    local sortHeroList = {}
    for k, v in pairs(heroList) do
        table.insert(sortHeroList, v)
    end

    local sortFun = function(hero1, hero2)
        local power1, power2 = hero1:GetPower(), hero2:GetPower()
        return power1 > power2
    end

    table.sort(sortHeroList, sortFun)
    return sortHeroList
end

function ModelHero:GetReverseHeroSortComp(record)
    local rec = record or {}
    local comp = function(hero1, hero2)
        local star1, star2 = hero1:GetStar(), hero2:GetStar()
        local lv1, lv2 = hero1:GetLv(), hero2:GetLv()
        local power1, power2 = hero1:GetPower(), hero2:GetPower()
        local refId1, refId2 = hero1:GetRefId(), hero2:GetRefId()
        local id1, id2 = hero1:GetId(), hero2:GetId()

        local isOneOn = rec[id1] and 1 or 2
        local isTwoOn = rec[id2] and 1 or 2
        if isOneOn ~= isTwoOn then
            return isOneOn > isTwoOn
        end

        if star1 ~= star2 then
            return star1 < star2
        end
        if lv1 ~= lv2 then
            return lv1 < lv2
        end
        if power1 ~= power2 then
            return power1 < power2
        end
        if refId1 ~= refId2 then
            return refId1 < refId2
        end
        return id1 < id2
    end

    return comp
end


-- 根据种族筛选英雄列表
function ModelHero:SelRaceHeroList(race, limStar, limLv)
    local selHeroList = {}
    local limit = limStar or limLv
    local heroList = self:GetHeroList()
    for k, v in pairs(heroList) do
        local serData = v:GetServerData()
        local refId = serData.refId
        local star = serData.star
        local id = serData.id
        local lv = serData.lv
        local ref = self:GetHeroRef(refId)
        if ref then
            local data
            local hRace = ref.raceType
            local maxStar = ref.maxStar
            if limStar then
                -- 限制等级大于最大等级 或者 英雄星级大于限制星级 则不加入列表中
                if limit < maxStar and star < limit then
                    data = serData
                end
            else
                if lv < limit then
                    data = serData
                end
            end
            if data then
                if race == 0 then
                    selHeroList[id] = data
                elseif race == hRace then
                    selHeroList[id] = data
                end
            end
        else
            LogError("表里没有找到refId = " .. refId)
        end
    end
    return selHeroList
end

-- 检查是否已拥有该英雄，通过refID
function ModelHero:CheckHaveHeroByRefId(refId)
    local heroList = self:GetHeroList()
    for k, v in pairs(heroList) do
        if refId == v:GetRefId() then
            return true
        end
    end
    return false
end

function ModelHero:SelRefIdHeroList(refId, limStar, limLv)
    local selHeroList = {}
    local limit = limStar or limLv
    local heroList = self:GetHeroList()
    for k, v in pairs(heroList) do
        local serData = v:GetServerData()
        local hrefId = serData.refId
        if hrefId == refId then
            local hstar = serData.star
            local id = serData.id
            local lv = serData.lv
            local ref = self:GetHeroRef(hrefId)
            if ref then
                local data = nil
                if limStar then
                    if hstar < limit then
                        data = serData
                    end
                elseif limit then
                    if lv < limit then
                        data = serData
                    end
                else
                    data = serData
                end
                if data then
                    selHeroList[id] = data
                end
            else
                LogError("表里没有找到refId = " .. refId)
            end
        end
    end
    return selHeroList
end

function ModelHero:CheckIsHaveOutfit(refId)
    local ref = self:GetHeroRef(refId)
    if ref then
        return ref.outfitRecastRate > 0
    end
    return false
end

function ModelHero:GetHaveRefIdHeroList()
    local list = {}
    local refIdRecordList = {}
    local heroList = self:GetHeroList()
    local refId
    for k, v in pairs(heroList) do
        if not v:IsTryHero() then
            refId = v:GetRefId()
            if self:CheckIsHaveOutfit(refId) and not refIdRecordList[refId] then
                refIdRecordList[refId] = true
                table.insert(list, {
                    refId = refId,
                })
            end
        end
    end
    return list
end

-- 根据refId获取第一个穿戴皮肤的伙伴
function ModelHero:GetHeroShowRefInSkin(refId)
    local heroSelList = self:SelRefIdHeroList(refId)
    local skin
    for k, serData in pairs(heroSelList) do
        skin = serData.skin
        if skin and skin > 0 then
            break
        end
    end
    if not skin or skin <= 0 then
        skin = self:GetHeroEffectByRefId(refId)
    end
    local effRef = gModelHero:GetShowEffectById(skin)
    return effRef
end

-- 如果hType不为空，根据hType选英雄，否则根据hRefId和hStar
function ModelHero:FilterHero(hRefId, hStar, hType, selHeroId, selHeroList, needNum, isSelWnd, otherSelectItem)
    local filterList = {}
    if self:IsUseYouHua() then
        local heroStarList = self._heroStarList                -- 记录 				英雄star 	-> 英雄id
        local heroStarSelInfo = heroStarList[hStar] or {}

        local other = ModelItem.RaceTypeList[hType]

        if hType then
            if hType == 0 then
                for tHeroId, tHeroStruct in pairs(heroStarSelInfo) do
                    if tHeroId ~= selHeroId and not tHeroStruct:IsTryHero() then
                        if not gModelSpiritHero:CheckIsSpiritHero(tHeroStruct:GetRefId()) then
                            local data
                            if selHeroList[tHeroId] then
                                data = tHeroStruct
                            else
                                if not self:IsHeroIdSel(tHeroId) then
                                    data = tHeroStruct
                                end
                            end
                            if data then
                                filterList[tHeroId] = data
                            end
                        end
                    end
                end

            elseif other then
                for race, v in pairs(other) do
                    for tHeroId, tHeroStruct in pairs(heroStarSelInfo) do
                        if tHeroId ~= selHeroId and not tHeroStruct:IsTryHero() then
                            if not gModelSpiritHero:CheckIsSpiritHero(tHeroStruct:GetRefId()) then
                                local data
                                if selHeroList[tHeroId] then
                                    data = tHeroStruct
                                else
                                    if not self:IsHeroIdSel(tHeroId) then
                                        data = tHeroStruct
                                    end
                                end
                                if data then

                                    local raceType = self:GetHeroType(tHeroStruct:GetRefId())
                                    if other[raceType] then
                                        filterList[tHeroId] = data
                                    end
                                end
                            end
                        end
                    end
                end

            else
                for tHeroId, tHeroStruct in pairs(heroStarSelInfo) do
                    if tHeroId ~= selHeroId and not tHeroStruct:IsTryHero() then
                        local raceType = self:GetHeroType(tHeroStruct:GetRefId())
                        if raceType == hType then
                            local data
                            if selHeroList[tHeroId] then
                                data = tHeroStruct
                            else
                                if not self:IsHeroIdSel(tHeroId) then
                                    data = tHeroStruct
                                end
                            end
                            if data then
                                filterList[tHeroId] = data
                            end
                        end
                    end
                end
            end
        else
            local heroRefIdList = self._heroRefIdList            -- 记录 				英雄refId 	-> 英雄id
            local heroRefIdSelInfo = heroRefIdList[hRefId] or {}
            for tHeroId, tHeroStruct in pairs(heroRefIdSelInfo) do
                if tHeroId ~= selHeroId and not tHeroStruct:IsTryHero() then
                    local isJoin = isSelWnd or tHeroStruct:GetLockStatus() ~= 1
                    if isJoin and heroStarSelInfo[tHeroId] then
                        local data
                        if selHeroList[tHeroId] then
                            data = tHeroStruct
                        else
                            if not self:IsHeroIdSel(tHeroId) then
                                data = tHeroStruct
                            end
                        end
                        if data then
                            filterList[tHeroId] = data
                        end
                    end
                end
            end
        end
    else
        -- 英雄筛选
        local heroList = self:GetHeroList()
        if heroList then
            for k, v in pairs(heroList) do
                local data
                local id = v:GetId()
                local isTry = v:IsTryHero()
                if id ~= selHeroId and not isTry then
                    local lock = v:GetLockStatus()
                    local isJoin = isSelWnd or lock ~= 1
                    if isJoin then
                        if hType then
                            local star = v:GetStar()
                            if hType == 0 and star == hStar then
                                if selHeroList[id] then
                                    data = v
                                else
                                    if not self:IsHeroIdSel(id) then
                                        data = v
                                    end
                                end
                            else
                                local refId = v:GetRefId()
                                local heroRef = self:GetHeroRef(refId)
                                if heroRef then
                                    local rType = heroRef.raceType
                                    if rType == hType and star == hStar then
                                        if selHeroList[id] then
                                            data = v
                                        else
                                            if not self:IsHeroIdSel(id) then
                                                data = v
                                            end
                                        end
                                    end
                                end
                            end
                        else
                            local refId = v:GetRefId()
                            local star = v:GetStar()
                            if refId == hRefId and star == hStar then
                                if selHeroList[id] then
                                    data = v
                                else
                                    if not self:IsHeroIdSel(id) then
                                        data = v
                                    end
                                end
                            end
                        end
                    end
                end
                if data then
                    filterList[k] = data
                end
            end
        end
    end
    local serHeroRace
    if selHeroId then
        local refId = self:GetRefIdById(selHeroId)
        local ref = self:GetHeroRef(refId)
        if ref then
            serHeroRace = ref.raceType
        end
    end
    local itemList = {}
    if hType then
        -- 英魂筛选(道具)
        local bagYingHunList = gModelItem:GetBagYingHunList()
        for k, v in pairs(bagYingHunList) do
            local itemRefData = gModelItem:GetYingHunRefByRefId(k)
            if itemRefData then
                local isIns = false
                local refRace, refStar = itemRefData.race, itemRefData.star

                --0时候的配置
                if hRefId == 0 and refStar == hStar then
                    isIns = true
                elseif serHeroRace and serHeroRace == refRace and refStar == hStar then
                    isIns = true
                elseif refRace == 0 and refStar == hStar then
                    isIns = true
                elseif refRace == hType and refStar == hStar then
                    isIns = true

                elseif (hType == 6 or hType == 7) and refStar == hStar then
                    --需要的为6类型 则 获取
                    local other = ModelItem.RaceTypeList[hType]
                    isIns = other and other[refRace] or false
                elseif refStar == hStar then
                    local other = ModelItem.RaceTypeList[refRace]
                    isIns = other and other[hType] or false
                end
                if isIns then
                    local itemStruct = gModelItem:GetItemServerDataByRefId(k)
                    if itemStruct then
                        local num = itemStruct._num

                        --这里被其他的地方选择了 所以弃掉一个
                        if otherSelectItem and otherSelectItem[itemStruct._refId] then
                            num = num - otherSelectItem[itemStruct._refId]
                            otherSelectItem[itemStruct._refId] = nil
                        end

                        for i = 1, num do
                            if needNum and needNum < i then
                                break
                            end
                            local key = "itemRace_" .. refRace .. "_" .. i
                            itemList[key] = itemStruct
                        end
                    end
                end
            end
        end
    end
    return filterList, itemList
end

function ModelHero:ClearUpStarSelHeroList()
    printInfoNR("清空升星选项")
    self._upStarSelHero = {}
end

function ModelHero:SetSelHeroId(id)
    local selHeroList = self._upStarSelHero
    if not selHeroList then
        selHeroList = {}
        self._upStarSelHero = selHeroList
    end
    local b = self:IsHeroIdSel(id)
    if b then
        selHeroList[id] = nil
    else
        selHeroList[id] = id
    end
end

-- true:选中了 false:没选中
function ModelHero:IsHeroIdSel(id)
    local selHeroList = self._upStarSelHero
    if table.isempty(selHeroList) then
        return false
    end
    if selHeroList[id] then
        return true
    else
        return false
    end
end

function ModelHero:SelItemUpHeroIdList(idList, itemType)
    if table.isempty(idList) then
        self._selItemUpHeroIdList = {}
        self._useItemType = nil
        return
    end
    local selList = self._selItemUpHeroIdList
    if not selList then
        selList = {}
        self._selItemUpHeroIdList = selList
    end
    for k, v in pairs(idList) do
        selList[k] = v
    end
    self._useItemType = itemType
end

function ModelHero:GetSelItemUpHeroIdList()
    return self._selItemUpHeroIdList, self._useItemType
end
