function ModelHero:GetRandomPrefabName()
    local ref = GameTable.CharacterEffectRef
    local refNum = table.keysize(ref)
    math.randomseed(tostring(os.time()))
    local rang = math.random(1, refNum)
    local start = 1
    for k, v in pairs(ref) do
        if start == rang then
            return v.name, v.prefabName
        end
        start = start + 1
    end
end
