function ModelHero:GetSkillListByRefIdAndStar(refId, starLv, form)

    local starRef = self:GetHeroStarRef(refId, form, starLv)
    if starRef then
        local heroSkillIdList = {}
        local heroSkillKeyList = {}
        local skillGroup = starRef.skillGroup
        local skillList = string.split(skillGroup, ",")
        for i = 1, #skillList do
            local data = skillList[i]
            local temp = string.split(data, "=")
            local skillId = tonumber(temp[1])
            local openClass = tonumber(temp[2])
            heroSkillIdList[#heroSkillIdList + 1] = {
                skillId = skillId,
                openClass = openClass
            }
            heroSkillKeyList[skillId] = openClass
        end
        return heroSkillIdList, heroSkillKeyList
    end
end

--获取解锁的技能id列表
function ModelHero:GetUnLockSkillIdListByHeroId(id, nextGrade)
    local starRef = self:GetStarRefById(id)
    if not starRef then
        return
    end
    --local hero = self:GetHeroById(id)
    --if hero then
    --	local refId = hero:GetRefId()
    --	local starLv = hero:GetStar()
    local hero = self:GetHeroById(id)
    local grade = hero:GetGrade()
    if nextGrade then
        grade = grade + 1
    end

    local heroSkillIdList = {}
    local skillGroup = starRef.skillGroup
    local skillList = string.split(skillGroup, ",")
    for i = 1, #skillList do
        local data = skillList[i]
        local temp = string.split(data, "=")
        local skillId = tonumber(temp[1])
        local needGrade = tonumber(temp[2]) or 0
        if needGrade <= grade then
            table.insert(heroSkillIdList, skillId)
        end
    end
    return heroSkillIdList

end

function ModelHero:GetSkillShowEffListBySkillRefId(skillId)
    local skillShowEffList = {}
    local skillRef = self:GetSkillByStarId(skillId)
    if skillRef then
        local skillEffectId = skillRef.skillEffect
        local skillEffectList = {}
        local needSplit = string.split(skillEffectId, "=")

        if needSplit and #needSplit > 2 then
            local str = needSplit[3]
            str = string.gsub(str, "{", "")
            str = string.gsub(str, "}", "")
            str = string.split(str, ",")
            for _i, _v in ipairs(str) do
                table.insert(skillEffectList, tonumber(_v))
            end
        else
            needSplit = string.split(skillEffectId, "|")
            if needSplit and #needSplit > 1 then
                for _i, _v in ipairs(needSplit) do
                    table.insert(skillEffectList, tonumber(_v))
                end
            else
                table.insert(skillEffectList, tonumber(skillEffectId))
            end
        end

        for index, skillId in ipairs(skillEffectList) do
            local skillEffectRef = self:GetSkillEffectByEffId(skillId)
            if skillEffectRef then
                local skillShowEff = skillEffectRef.skillShowEff
                if skillShowEff then
                    table.insert(skillShowEffList, tonumber(skillShowEff))
                end
            end
        end
    end
    return skillShowEffList
end

