function ModelHero:GetClassGradeByRefIdAndStar(refId, star)
    local heroRef = self:GetHeroRef(refId)
    if not heroRef then
        return
    end
    local classType = heroRef.classType
    local typeSortHeroClassRefList = self._typeSortHeroClassRefList
    local classTypeList = typeSortHeroClassRefList[classType] or {}
    table.sort(classTypeList, function(a, b)
        return a.grade < b.grade
    end)
    local grade = -1
    local maxStar = 0
    for i, v in ipairs(classTypeList) do
        local needStar = v.needStar
        if needStar == -1 and star >= maxStar then
            grade = v.grade
        elseif star >= needStar then
            grade = v.grade
        end
        maxStar = needStar
    end
    return grade
end

function ModelHero:ConvertToHeroGradeId(classType, grade)
    local classId = classType * 10 + grade                    -- 阶级Id
    return classId
end

-- 属性计算
function ModelHero:GetBaseAttrInfo(refId, lv, starId, gradeId, addBuffList)
    local Atk, maxHp, Def, Speed = 0, 0, 0, 0
    local heroRef = self:GetHeroRef(refId)
    if not heroRef then
        return Atk, maxHp, Def, Speed
    end
    local starRef = self:GetHeroStarById(starId)
    local gradeRef = self:GetHeroClassById(gradeId)

    return self:GetBaseAttrInfoImpl(lv, heroRef, starRef, gradeRef, addBuffList)

end

function ModelHero:GetBaseAttrInfoImpl(lv, heroRef, starRef, gradeRef, addBuffList)
    local Atk, maxHp, Def, Speed = 0, 0, 0, 0
    if not addBuffList then
        addBuffList = {}
    end
    -- 被动技能增幅系数累和
    local atrPerNum = addBuffList[LAttrConst.Atk] and addBuffList[LAttrConst.Atk][2] or 0
    local speedPerNum = addBuffList[LAttrConst.Speed] and addBuffList[LAttrConst.Speed][2] or 0
    local maxHpPerNum = addBuffList[LAttrConst.MaxHP] and addBuffList[LAttrConst.MaxHP][2] or 0
    local defPerNum = addBuffList[LAttrConst.Def] and addBuffList[LAttrConst.Def][2] or 0

    -- 被动技能固定值
    local atkAddNum = addBuffList[LAttrConst.Atk] and addBuffList[LAttrConst.Atk][1] or 0
    local speedAddNum = addBuffList[LAttrConst.Speed] and addBuffList[LAttrConst.Speed][1] or 0
    local maxHpAddNum = addBuffList[LAttrConst.MaxHP] and addBuffList[LAttrConst.MaxHP][1] or 0
    local defAddNum = addBuffList[LAttrConst.Def] and addBuffList[LAttrConst.Def][1] or 0

    --local allModelNum = 0                            -- 各个模块固定值累和
    --local allModelParNum = 0                        -- 各个模块固定值累和 percent:百分比

    local baseAtk = heroRef.Atk                -- 初始值
    local growAtk = heroRef.growAtk            -- 成长系数
    local atkSVal = starRef.atkVal            -- 星级系数
    local atkGVal = gradeRef.atkVal            -- 阶级系数
    local atkSEx = starRef.atkEx                -- 星级固定值
    local atkGEx = gradeRef.atkEx            -- 阶级固定值

    local baseMaxHp = heroRef.MaxHP
    local growMaxHp = heroRef.growMaxHp
    local maxHpSVal = starRef.maxhpVal
    local maxHpGVal = gradeRef.maxhpVal
    local maxHpSEx = starRef.maxhpEx
    local maxHpGEx = gradeRef.maxhpEx

    local baseDef = heroRef.Def
    local growDef = heroRef.growDef
    local defSVal = starRef.defVal
    local defGVal = gradeRef.defVal
    local defSEx = starRef.defEx
    local defGEx = gradeRef.defEx

    local baseSpeed = heroRef.Speed
    local growSpeed = heroRef.growSpeed
    local speedSVal = starRef.speedVal
    local speedGVal = gradeRef.speedVal
    local speedSEx = starRef.speedEx
    local speedGEx = gradeRef.speedEx

    -- （（初始值 + 等级 * 成长系数 * 阶级系数 * 星级系数）* （1 + 被动技能增幅系数）+ 被动技能固定值加成累和 + 阶级固定值 + 星级固定值 + 各个模块固定值累和）* （ 1 + 各个模块百分比加成累和 ）
    --[[
		Atk = ((baseAtk + lv * growAtk * atkSVal * atkGVal) * (1 + atrPerNum) + atkSEx + atkGEx + allModelNum) * (1 + allModelParNum) + atkAddNum
		maxHp = ((baseMaxHp + lv * growMaxHp * maxHpSVal * maxHpGVal) * (1 + maxHpPerNum) + maxHpSEx + maxHpGEx + allModelNum) * (1 + allModelParNum) + maxHpAddNum
		Def = ((baseDef + lv * growDef * defSVal * defGVal) * (1 + defPerNum) + defSEx + defGEx + allModelNum) * (1 + allModelParNum) + defAddNum
		Speed = ((baseSpeed + lv * growSpeed * speedSVal * speedGVal) * (1 + speedPerNum) + speedSEx + speedGEx + allModelNum) * (1 + allModelParNum) + speedAddNum]]

    -- 3.0修改公式
    -- 英雄基础属性=（初始值 + 等级 * 成长系数 * 阶级系数 * 星级系数）* （1 + 被动技能增幅百分比系数累和）+ 被动技能固定值加成累和 + 阶级固定值 + 星级固定值）
    Atk = (baseAtk + lv * growAtk * atkSVal * atkGVal) * (1 + atrPerNum) + atkAddNum + atkGEx + atkSEx
    maxHp = (baseMaxHp + lv * growMaxHp * maxHpSVal * maxHpGVal) * (1 + maxHpPerNum) + maxHpAddNum + maxHpGEx + maxHpSEx
    Def = (baseDef + lv * growDef * defSVal * defGVal) * (1 + defPerNum) + defAddNum + defGEx + defSEx
    Speed = (baseSpeed + lv * growSpeed * speedSVal * speedGVal) * (1 + speedPerNum) + speedAddNum + speedGEx + speedSEx


    --printInfoN2("cjh------------计算攻击的各个模块的数据", "baseAtk--"..baseAtk.."--lv--"..lv.."--growAtk--"..growAtk.."--atkSVal--"..atkSVal.."--atkGVal--"..atkGVal.."--atrPerNum--"..atrPerNum.."--atkAddNum--"..atkAddNum.."--atkGEx--"..atkGEx.."--atkSEx--"..atkSEx)
    --printInfoN2("cjh------------计算攻击的各个模块的数据--计算的部分的值", "--value1--"..(baseAtk + lv * growAtk * atkSVal * atkGVal).."--value2--".. (1 + atrPerNum).."--value3--"..(atkAddNum + atkGEx + atkSEx))
    --
    return Atk, maxHp, Def, Speed
end

