function ModelHero:GetSkillBuffInter(heroSkillIdList)
    local buffList = {}
    if not table.isempty(heroSkillIdList) then
        for i, v in ipairs(heroSkillIdList) do
            local skillRef = self:GetSkillByStarId(v.skillId)
            if skillRef then
                local skillEffectId = skillRef.skillEffect
                local skillEffectList = {}
                local needSplit = string.split(skillEffectId, "=")
                if needSplit and #needSplit > 2 then
                    local str = needSplit[3]
                    str = string.gsub(str, "{", "")
                    str = string.gsub(str, "}", "")
                    str = string.split(str, ",")
                    for _i, _v in ipairs(str) do
                        table.insert(skillEffectList, tonumber(_v))
                    end
                else
                    skillEffectId = string.split(skillEffectId, "|")
                    for _i, _v in ipairs(skillEffectId) do
                        table.insert(skillEffectList, tonumber(_v))
                    end
                end
                for index, skillId in ipairs(skillEffectList) do
                    local skillEffectRef = self:GetSkillEffectByEffId(skillId)
                    if skillEffectRef then
                        local pasvEffect = skillEffectRef.pasvEffect
                        if not string.isempty(pasvEffect) then
                            local pasvEffectList = string.split(pasvEffect, ",")
                            for pasvIndex, pasvVal in ipairs(pasvEffectList) do
                                local valueList = string.split(pasvVal, "=")
                                local attr, attrType, attrVal = tonumber(valueList[1]), tonumber(valueList[2]), tonumber(valueList[3])
                                local listData = buffList[attr]
                                if not listData then
                                    listData = {}
                                    buffList[attr] = listData
                                end
                                local typeData = listData[attrType]
                                if not typeData then
                                    typeData = 0
                                end
                                listData[attrType] = typeData + attrVal
                            end
                        end
                    end
                end
            end
        end
    end
    return buffList
end

