function ModelHero:GetAttributeValueNoNameByIdAndVal(id, type, attrVal)
    local ref = self:GetAttributeRefById(id)
    if not ref then
        printErrorN(string.format("no attr cfg id %s", id))
        return ""
    end

    if type == 3 then
        if ref.numType == 2 then
            -- 百分比值
            attrVal = attrVal * 100
        end
        if ref.saveNum == 0 then
            -- 取整
            attrVal = math.round2(attrVal)
        else
            attrVal = math.round(attrVal, ref.saveNum)
        end

        if ref.numType == 2 then
            return attrVal .. "%"
        end
        return attrVal
    end

    local showNumType = (type == 1 and ref.numType == 1) and 1 or 2

    if showNumType == 1 then
        return attrVal
    else
        return (attrVal * 100) .. "%"
    end

    --if(ref.numType==1)then
    --	if(type==2)then
    --		return (attrVal*100).."%"
    --	end
    --	return attrVal
    --else
    --	return (attrVal*100).."%"
    --end
end

