    end
end

function ModelHero:PlayHeroRoleSound(refId, skinOrEffectId, isMon, isPet)
    local showEffect
    skinOrEffectId = skinOrEffectId or 0
    if skinOrEffectId > 0 then
        -- 【C宠物系统】删掉宠物系统相关
        -- if(isPet)then
        -- 	showEffect = GameTable.PetEffectRef[skinOrEffectId]
        -- else
        showEffect = self:GetShowEffectById(skinOrEffectId)
        -- end
    end
    if not showEffect then
        if isMon then
            local monRef = GameTable.MonsterAttrRef[refId]
            if monRef then
                showEffect = self:GetShowEffectById(monRef.effectId)
            end
        else
            showEffect = self:GetShowEffectById(self:GetHeroEffectByRefId(refId))
        end
    end
    if not showEffect then
        return
    end
    local dataStr = showEffect.RoleRef or ""
    local arrList = LxDataHelper.ParseStringParam_Semicolon(dataStr)
    if not arrList or #arrList == 0 then
        return
    end
    local len = #arrList
    local soundName
    if len == 1 then
        soundName = arrList[1]
    else
        local rand = math.floor(math.random() * 10000)
        local index = rand % len + 1
        soundName = arrList[index]
    end
    if string.isempty(soundName) then
        return
    end
    if LOG_INFO_ENABLED then
        printInfoNR("===== soundName = " .. soundName)
    end
    if not gLGameAudio then
        return
    end
    gLGameAudio:PlaySingleSound(soundName)
end

