function ModelHero:CheckHeroSkinIsUpImpl(id)
    local status = false
    local heroData = self:GetHeroStructById(id)
    if not heroData then
        return status
    end
    local starId = self:GetStarIdById(id)
    local HeroStarRefList = self._HeroStarRefList
    local skinList = HeroStarRefList and HeroStarRefList[starId]
    if not skinList then
        return status
    end

    local refId = heroData:GetRefId()

    for k, v in pairs(skinList) do
        if status then
            break
        end
        local isExamine = true
        local haveSkinData = self:GetHeroRefIdSkinListByHeroRefId(refId)
        if haveSkinData then
            local skinData = haveSkinData[k]
            if skinData then
                local skinTime = tonumber(skinData.endTime)
                if skinTime ~= -1 then
                    skinTime = skinTime / 1000
                    local curTime = GetTimestamp()
                    isExamine = skinTime < curTime
                else
                    isExamine = false
                end
            end
        else
            isExamine = true
        end
        if isExamine then
            status = self:CheckOpenSkinItemStatus(k)
        end
    end
    return status
end

function ModelHero:CheckOpenSkinItemStatus(effectId, heroRefId)
    if heroRefId then
        local haveSkinData = self:GetHeroRefIdSkinListByHeroRefId(heroRefId)
        if haveSkinData then
            local skinData = haveSkinData[effectId]
            if skinData then
                local skinTime = tonumber(skinData.endTime)
                if skinTime ~= -1 then
                    skinTime = skinTime / 1000
                    local curTime = GetTimestamp()
                    local isExamine = skinTime >= curTime
                    if isExamine then
                        return false
                    end
                else
                    return false
                end
            end
        end
    end
    local status = false
    local HeroEffectRefList = self._HeroEffectRefList
    local effectData = HeroEffectRefList and HeroEffectRefList[effectId]
    if effectData then
        for item, itemRefId in pairs(effectData) do
            if status then
                break
            end
            local bagNum = gModelItem:GetNumByRefId(itemRefId)
            status = bagNum > 0
        end
    end
    return status

end

--检测是否拥有永久皮肤
function ModelHero:CheckFovSkinItem(effectId, heroRefId)
    if heroRefId then
        local haveSkinData = self:GetHeroRefIdSkinListByHeroRefId(heroRefId)
        if haveSkinData then
            local skinData = haveSkinData[effectId]
            if skinData then
                local skinTime = tonumber(skinData.endTime)
                if skinTime == -1 then
                    return true
                end
            end
        end
    end
    local status = false
    local HeroEffectRefList = self._HeroEffectRefList
    local effectData = HeroEffectRefList and HeroEffectRefList[effectId]
    if effectData then
        for item, itemRefId in pairs(effectData) do
            if status then
                break
            end
            local itemRef = gModelItem:GetRefByRefId(itemRefId)
            local typeDate = itemRef.typeDate
            local dateArr = string.split(typeDate, "=")
            if (dateArr and dateArr[2] == "-1") then
                local bagNum = gModelItem:GetNumByRefId(itemRefId)
                status = bagNum > 0
            end
        end
    end
    return status
end

--检查列表中满足星级是否满足n个  @arg_1 heroList 必须是从1开始的列表
function ModelHero:CheckHeroListIsEnoughtStarCount(heroList, needStar, needCountr)

    local count = 0
    for k, v in ipairs(heroList) do
        if v._star >= needStar then
            count = count + 1

            if count >= needCountr then
                return true
            end
        end
    end

    return false
end

function ModelHero:GetEffectItemId(effectId)
    local HeroEffectRefList = self._HeroEffectRefList
    local effectData = HeroEffectRefList and HeroEffectRefList[effectId]
    if effectData then
        for item, itemRefId in pairs(effectData) do
            local itemRef = gModelItem:GetRefByRefId(itemRefId)
            if itemRef then
                local typeDate = itemRef.typeDate
                local dateArr = string.split(typeDate, "=")
                if (dateArr and dateArr[2] == "-1") then
                    local bagNum = gModelItem:GetNumByRefId(itemRefId)
                    if (bagNum > 0) then
                        return itemRefId
                    end
                end
            else
                if LOG_INFO_ENABLED then
                    LogError("GameTable.PlayerItemRef[refId] is not find, refId = " .. (itemRefId or "nil"))
                end
            end
        end
    end
end

-- refId  needStar  多种形态的整理  tongguo refId 获取到对应的数据 GameTable.CharacterEffectRef[refId]  这里传入refId 不为空 则有多形态
function ModelHero:GetPolymorphism(originId)
    local isOpen = gModelHeroExtra:CheckIsOpenForm()
    if not isOpen then
        return
    end

    if not self._polymorphism then
        self:InitEffectRef()
    end
    return self._polymorphism[originId]
end

function ModelHero:GetOriginId(refId)
    return self._originId[refId]
end

--- 判断英雄是否有这个皮肤
function ModelHero:CheckHeroRefIdHasSkinId(skinId)
    local effectRef = self:GetShowEffectById(skinId)
    if not effectRef then
        return false
    end

    local heroType = effectRef.heroType
    if not self._recordHeroSkinMap[heroType] then
        return false
    end

    return self._recordHeroSkinMap[heroType][skinId]
end

function ModelHero:GetHeroSkinListByHeroRefId(heroRefId)
    local skinMap = self._recordHeroSkinMap[heroRefId]
    if not skinMap then
        return {}
    end

    local list = {}
    for i, v in pairs(skinMap) do
        table.insert(list, i)
    end
    table.sort(list, function(a, b)
        return a < b
    end)
    return list
end

-- 升星的时候判断是否要形态变化
function ModelHero:GetUpStarPolymorphism(refid, oldstar, newstar)
    local polymorphism = self:GetPolymorphism(refid)

    local oldRefID, newRefId = 0, 0

    if not polymorphism then
        return oldRefID, newRefId
    end

    for k, v in ipairs(polymorphism) do


        if oldstar > v.needStar then
            oldRefID = v.refId
        end

        if newstar == v.needStar then
            newRefId = v.refId

            if oldRefID == 0 then
                oldRefID = refid
            end

            return oldRefID, newRefId
        end
    end

    if oldRefID == 0 then
        oldRefID = refid
    end

    return oldRefID, 0
end

--- 仅用于魔塔红点检测
function ModelHero:GetHeroUpStarStatus(heroTypeList, status)
    local heroList, heroStatus = self:GetHeroList()
    if not heroList or not heroStatus then
        return false
    end

    local curTime = GetTimestamp()
    local motaUpStarCheckTime = tonumber(LPlayerPrefs.motaUpStarCheckTime)
    if motaUpStarCheckTime and motaUpStarCheckTime > 0 and not self._motaUpStarRedPointRecord then
        local checkY, checkM, checkD = LUtil.GetYmdByTimestamp(motaUpStarCheckTime)
        local curY, curM, curD = LUtil.GetYmdByTimestamp(curTime)
        if curY == checkY and curM == checkM and curD == checkD then
            return false
        end
    end

    local sortHeroList = {}
    local resonanceLevel = gModelResonance:GetResonanceLv()
    local getUpStarStatus = false
    local heroUpStarLimit = gModelHeroSpirit:GetUpStarLimit()
    for k, v in pairs(heroList) do
        if getUpStarStatus then
            break
        end
        local refId = v:GetRefId()
        local ref = self:GetHeroRef(refId)
        if ref then
            local goNext = true
            local raceType = ref.raceType
            if heroTypeList then
                goNext = heroTypeList[raceType] ~= nil
            else
                goNext = true
            end
            if goNext then
                local star = v:GetStar()
                local upStarInfo = self:GetUpStarHeroInfoByHeroRefIdAndStar(refId, star)
                if upStarInfo then
                    local nextStar = star + 1
                    local maxStar = ref.maxStar
                    if upStarInfo.upStar == 1 then
                        local id = v._id
                        local upStarAppoint, upStarRange, upStarItem = upStarInfo.upStarAppoint, upStarInfo.upStarRange, upStarInfo.upStarItem
                        local data = {}
                        local fuse1, fuse2, fuse3 = true, true, true
                        for _i, _v in ipairs(upStarAppoint) do
                            if not fuse1 then
                                break
                            end
                            local needRefId, needStar, needNum = _v.needRefId, _v.needStar, _v.needNum
                            local dataList = self:FilterHero(needRefId, needStar, nil, id, {}, needNum)
                            local haveNum = table.keysize(dataList)
                            local tempList = {}
                            local aaa = 0
                            for key, val in pairs(dataList) do
                                if aaa >= needNum then
                                    break
                                end
                                tempList[key] = val
                                aaa = aaa + 1
                            end
                            table.insert(data, tempList)
                            fuse1 = haveNum >= needNum
                        end
                        if fuse1 then
                            for _i, _v in ipairs(upStarRange) do
                                if not fuse2 then
                                    break
                                end
                                local needRefId, needStar, needNum = _v.needRefId, _v.needStar, _v.needNum
                                local dataList, yinghunItemList = self:FilterHero(needRefId, needStar, needRefId, id, {}, needNum)
                                local haveNum = table.keysize(dataList) + table.keysize(yinghunItemList)
                                local selNum = 0
                                for dataIndex, dataVal in ipairs(data) do
                                    for key, value in pairs(dataVal) do
                                        if dataList[key] then
                                            selNum = selNum + 1
                                        end
                                    end
                                end
                                haveNum = haveNum - selNum
                                fuse2 = haveNum >= needNum
                            end
                            if fuse2 then
                                for _i, _v in ipairs(upStarItem) do
                                    if not fuse3 then
                                        break
                                    end
                                    local itemRefId, num = _v.itemId, _v.itemNum
                                    local haveNum = gModelItem:GetNumByRefId(itemRefId)
                                    fuse3 = haveNum >= num
                                end
                            end
                        end
                        local fuse = fuse1 and fuse2 and fuse3
                        local temp = 0
                        if fuse then
                            local upStarLimit
                            if maxStar < nextStar then
                                upStarLimit = heroUpStarLimit[star]
                            else
                                upStarLimit = heroUpStarLimit[nextStar]
                            end
                            local isAdd = true
                            if upStarLimit then
                                isAdd = upStarLimit <= resonanceLevel
                            end
                            if isAdd then
                                temp = 1
                            end
                            if status and temp == 1 then
                                getUpStarStatus = true
                            end
                            if gModelSpiritHero:CheckIsSpiritHero(refId) then
                                temp = 0
                            end
                        end
                        v:SetFuseStatus(temp)
                        table.insert(sortHeroList, v)
                    end
                end
            else
                printInfoNR("========== 没有找到对应的refId数据 ：" .. refId)
            end
        end
    end
    if status then
        self._motaUpStarRedPointRecord = true
        LPlayerPrefs.SetMotaUpStarCheckTime(curTime)
        return getUpStarStatus
    else
        return sortHeroList
    end
end

-- 自动填充排序
function ModelHero:SortFillHeroList(selHeroList)
    local list = {}
    for k, v in pairs(selHeroList) do
        if v._status == 0 then
            table.insert(list, v)
        end
    end
    table.sort(list, function(hero1, hero2)
        local lv1, lv2 = hero1._level, hero2._level
        if lv1 ~= lv2 then
            return lv1 < lv2
        else
            local fightPower1, fightPower2 = hero1._fightPower, hero2._fightPower
            if fightPower1 ~= fightPower2 then
                return fightPower1 < fightPower2
            else
                return hero1._id < hero2._id
            end
        end
    end)
    return list
end

