function ModelHero:ReqShowHeroTip(playerId, heroData, share, shareFunc, upLayer, serverId)

    local data = {
        playerId = playerId,
        heroData = heroData,
        share = share,
        shareFunc = shareFunc,
        upLayer = upLayer,
        serverId = serverId,
    }

    if not heroData.form then
        heroData.form = gModelHero:GetHeroForm(heroData.id)
    end

    self:ReqShowHeroTipEx(data)
end

function ModelHero:ReqShowHeroTipEx(data)
    local playerId = data.playerId
    if string.isempty(playerId) then
        playerId = gModelPlayer:GetPlayerId()
    end

    local para = {
        playerId = playerId,
        heroData = data.heroData,
        share = data.share,
        shareFunc = data.shareFunc,
        serverId = data.serverId,
        upLayer = data.upLayer,
        wndType = 2
    }
    self._reqHeroPara = para

    local heroId = data.heroData.id
    local heroType = data.heroData.heroType or 1
    local other = data.heroData.other

    self:OnHeroAttributeReq(heroId, playerId, heroType, data.serverId, 1, other)
end

function ModelHero:OnShowShareHeroTip(playerId, heroData, share, shareFunc, upLayer, serverId)
    if string.isempty(playerId) then
        return
    end
    if not heroData.heroAttr then
        self:ReqShowHeroTip(playerId, heroData, share, shareFunc, upLayer, serverId)
        return
    end
    local para = {
        playerId = playerId,
        heroData = heroData,
        share = share,
        shareFunc = shareFunc,
        serverId = serverId,
        upLayer = upLayer,
        wndType = 2
    }
    self._reqHeroPara = para
    self:OnHeroAttributeResp(heroData.heroAttr)
end

