function ModelHero:GetHeroIcon(refId, star, skin, form)
    local iconBgPath = ""
    local iconPath = "icon_hero_0001"
    local heroRef = self:GetHeroRef(refId)
    if heroRef then
        --local starType = heroRef.starType
        --local starId = LUtil.GetStarId(starType, star)
        local starRef = self:GetHeroStarRef(refId, form, star)
        local effectShowId
        local quality
        if gLGameLanguage:IsUSARegion() then
            quality = heroRef.quality
        else
            if starRef then
                quality = starRef.quality

            end
        end

        if quality then
            local qualityRef = gModelItem:GetQualityRef(quality)
            if qualityRef then
                iconBgPath = qualityRef.iconBg
            end

            if starRef then
                effectShowId = starRef.effectId
            end
        end

        --皮肤展示
        if skin and skin > 0 then
            effectShowId = skin
        end

        if effectShowId then
            local effectRef = self:GetShowEffectById(effectShowId)
            if effectRef then
                iconPath = effectRef.icon
            end
        end
    end

    return iconPath, iconBgPath
end

function ModelHero:GetMonsterIcon(refId, quality)
    local iconBgPath = ""
    local iconPath = "icon_hero_0001"
    local monRef = self:GetMonsterAttrByRefId(refId)
    if monRef then

        quality = quality or monRef.quality

        local qualityRef = gModelItem:GetQualityRef(quality)
        if qualityRef then
            iconBgPath = qualityRef.iconBg
        end

        local effectShowId = monRef.effectId
        local effectRef = self:GetShowEffectById(effectShowId)
        if effectRef then
            iconPath = effectRef.icon
        end
    end

    return iconPath, iconBgPath
end

function ModelHero:OnHeroPowerRefreshStateReq(id)
    local pb = LProtoHelper.CreateProto(LProtoIds.HeroPowerRefreshStateReq)
    pb.id = id
    SendMessage(pb, LProtoIds.HeroPowerRefreshStateReq)
end

function ModelHero:OnHeroPowerRefreshStateResp(pb, ret)
    local refreshPowHeroList = self._refreshPowHeroList
    if not refreshPowHeroList then
        refreshPowHeroList = {}
        self._refreshPowHeroList = refreshPowHeroList
    end
    local heroInfo = pb.heroInfo
    for i, v in ipairs(heroInfo) do
        local id = v.id
        refreshPowHeroList[id] = { id = id, state = v.state }
    end
end

function ModelHero:FindHeroPowStateById(id)
    if not id then
        return
    end
    local heroList = self._heroList
    if not heroList then
        return
    end
    local myHero = heroList[id] ~= nil
    if not myHero then
        return
    end
    local refreshPowHeroList = self._refreshPowHeroList
    if not refreshPowHeroList then
        return
    end
    local heroInfo = refreshPowHeroList[id]
    if not heroInfo then
        return
    end
    local state = heroInfo.state
    if state == 1 then
        self:OnHeroPowerRefreshStateReq(id)
    end
end

