function ModelHero:GetInvasionNpcData(refId)
    local heroRef = self:GetHeroRef(refId)
    if not heroRef then
        printErrorN(string.format("no hero ref %s", refId))
        return
    end
    local initStar = heroRef.initStar
    local starType = heroRef.starType
    local starId = self:GetStarId(starType, initStar)
    local starRef = self:GetHeroStarById(starId)
    local effectId = starRef.effectId
    local commonSkill = starRef.commonSkill
    local activeSkillGroup = starRef.activeSkillGroup
    local strs = string.split(activeSkillGroup, ",")
    local skillDataList = {}

    local expreId = gModelSkill:GetExpreIdBySkill(commonSkill)
    if expreId then
        local data = {
            skillId = commonSkill,
            isNormal = true,
            expreId = expreId
        }
        table.insert(skillDataList, data)
    end

    for k, v in ipairs(strs) do
        local tempStrs = string.split(v, "=")
        local skillId = tonumber(tempStrs[1])
        expreId = gModelSkill:GetExpreIdBySkill(skillId)
        if expreId then
            local data = {
                skillId = skillId,
                isNormal = false,
                expreId = expreId
            }
            table.insert(skillDataList, data)
        end
    end

    local npcData = {
        effectId = effectId,
        skillDataList = skillDataList,
    }

    return npcData
end

