function ModelHero:GetStarHeroList(star, race)
    star = star or 4
    local list = {}
    local refIdNumList = {}
    local heroList = self:GetHeroList()
    for k, v in pairs(heroList) do
        local curStar = v:GetStar()
        if star == curStar then
            local refId = v:GetRefId()
            local refIdNum = refIdNumList[refId] or 0
            refIdNum = refIdNum + 1
            refIdNumList[refId] = refIdNum
            local ins = true
            if race and race ~= 0 then
                local curRace = self:GetHeroType(refId)
                if gModelSpiritHero:IsSpiritHeroRaceType(curRace) then
                    ins = false
                else
                    ins = curRace and curRace == race
                end
            else
                local curRace = self:GetHeroType(refId)
                if gModelSpiritHero:IsSpiritHeroRaceType(curRace) then
                    ins = false
                end
            end
            if ins then
                table.insert(list, v:GetServerData())
            end
        end
    end
    return list, refIdNumList
end

