function ModelHero:GetTryHeroOnlyShowData(refId, refType)
    local heroFreeAttrRef = gModelItem:GetCurItemHeroFreeAttrRef(refId)
    if not heroFreeAttrRef then
        return nil
    end

    local star = heroFreeAttrRef.star
    if refType and refType == ModelItem.Item_SELECT_TRY_SPIRITHERO then
        star = 0
    end

    local lv = heroFreeAttrRef.level
    local iconBgPath
    local iconPath
    local raceIcon

    local heroRef = self:GetHeroRef(refId)
    local starType = heroRef.starType
    local starId = self:GetStarId(starType, star)
    local starRef = self:GetHeroStarById(starId)
    local effectShowId
    local quality
    if gLGameLanguage:IsUSARegion() then
        quality = heroRef.quality
    else
        if starRef then
            quality = starRef.quality
        end
    end

    if quality then
        local qualityRef = gModelItem:GetQualityRef(quality)
        if qualityRef then
            iconBgPath = qualityRef.iconBg
        end

        if starRef then
            effectShowId = starRef.effectId
        end
    end

    local effectRef = self:GetShowEffectById(effectShowId)
    if effectRef then
        iconPath = effectRef.icon
    end

    local typeId = heroRef.raceType
    local raceRef = self:GetHeroRaceRef()[typeId]
    if raceRef then
        raceIcon = raceRef.icon
    end

    local data = {
        iconPath = iconPath,
        iconBgPath = iconBgPath,
        raceImg = raceIcon,
        star = star,
        lv = lv,
    }

    return data
end

