---@param hero StructHero
function ModelHero:CheckHeroCanUp(hero)
    local star = hero:GetStar()
    local refId = hero:GetRefId()
    local heroRef = self:GetHeroRef(refId)
    --local starType = heroRef.starType
    --local starId = self:GetStarId(starType, star)
    local starRef = self:GetStarRefById(hero:GetId())    -- 星级表
    local maxLevel = starRef.maxLevel
    local lv = hero:GetLv()
    if lv == maxLevel then
        return false
    else
        local grade = hero:GetGrade()
        local classType = heroRef.classType                -- 阶级数据
        local classId = self:ConvertToHeroGradeId(classType, grade)    -- 阶级Id
        local classRef = self:GetHeroClassById(classId)    -- 阶级表
        local needLv, needStar = classRef.needLevel, classRef.needStar
        if needLv == lv then
            if needStar <= star then
                return gModelGeneral:CheckConsumeFill(classRef.needItem)
            else
                return false
            end
        else
            return self:CheckCanUpLevel(hero)
        end
    end
end

