---@param hero StructHero  英雄是否可升级
function ModelHero:CheckCanUpLevel(hero)
    local lv = hero:GetLv()
    local lvRef = gModelHero:GetHeroLevelById(lv)
    local expNeed, goldNeed = lvRef.needExp, lvRef.needGold
    if expNeed < 0 or goldNeed < 0 then
        return false
    end
    local expOwn = gModelItem:GetNumByRefId(104001)
    local goldOwn = gModelItem:GetNumByRefId(101001)
    if expOwn < expNeed or goldOwn < goldNeed then
        return false
    end

    return true
end

function ModelHero:GetEffectRefAttrByRefId(refId)
    local effectRef = self:GetShowEffectById(refId)
    if not effectRef then
        return
    end
    local attr = effectRef.attr
    if string.isempty(attr) then
        return
    end
    local attrList = {}
    attr = string.split(attr, ",")
    for i, v in ipairs(attr) do
        v = string.split(v, "=")
        local attrRefId, attrType, attrValue = tonumber(v[1]), tonumber(v[2]), tonumber(v[3])
        local attrName = self:GetAttributeNameById(attrRefId)
        local attrStr = self:GetAttributeValueNoNameByIdAndVal(attrRefId, attrType, attrValue)
        table.insert(attrList, {
            name = attrName,
            attr = attrStr
        })
    end
    return attrList
end

function ModelHero:SetNeedHeroPowerTips(needShow, heroId)
    self._needShowHeroPowerTips = needShow or false
    self._needShowPowerTipsHeroId = heroId
    self._heroTipAttrChangData = {}
    self._heroTipPowerChangData = {}
