function ModelHero:TryShowHeroPowerTips()
    if not self:GetNeedHeroPowerTips() then
        return
    end
    if table.isempty(self._heroTipAttrChangData) or not self._heroTipAttrChangData.isReceived then
        return
    end
    if table.isempty(self._heroTipPowerChangData) or not self._heroTipPowerChangData.isReceived then
        return
    end

    local subValue = self._heroTipPowerChangData.subValue
    if subValue <= 0 then
        self:SetNeedHeroPowerTips(false)
        return
    end

    local dataList = self._heroTipAttrChangData.data
    local powerPre = self._heroTipPowerChangData.powerPre

    gModelGeneral:OpenHeroPowerTip(dataList, powerPre, subValue)
    self:SetNeedHeroPowerTips(false)
end

