--获取最高战力流水id
function ModelHero:GetRefIdTypeList(refId)
    local list = {}
    local heroList = self:GetHeroList()
    for id, hero in pairs(heroList) do
        if hero:GetRefId() == refId then
            table.insert(list, {
                id = hero:GetId(),
                power = hero:GetPower(),
            })
        end
    end
    if #list < 1 then
        return
    end
    table.sort(list, function(a, b)
        return a.power > b.power
    end)
    return list[1].id
end

