function ModelHero:GetMaxPowerMonsterAttrRef(refId)
    local monsterList = self:GetMonsterList(refId)
    local monsterRef, maxPower
    for k, v in ipairs(monsterList) do
        local temp = self:GetMonsterAttrByRefId(v)
        if not maxPower or maxPower < temp.monsterPower then
            maxPower = temp.monsterPower
            monsterRef = temp
        end
    end
    if not monsterRef then
        printErrorN2("怪物阵型表", string.format("缺少配置 refid %s", refId))
