---isSkinItem,State: 1,未拥有；2,未激活；3,未穿戴；4,已穿戴
function ModelHero:GetSkinStateByItemId(itemdata)
    if itemdata.itemType ~= LItemTypeConst.TYPE_ITEM then
        return false
    end
    local itemId = itemdata.itemId
    local skinRefId = gModelItem:GetSkinRefIdByItemId(itemId)
    if not skinRefId then
        return false
    end

    local skinInfo = self:GetHeroSkinInfoByRefId(skinRefId)
    if skinInfo then
        if tonumber(skinInfo.endTime) == -1 then
            if string.isempty(skinInfo.heroId) then
                return true, 3, skinRefId
            else
                return true, 4, skinRefId
            end
        end
    end

    local itemNum = gModelItem:GetNumByRefId(itemId)
    if itemNum > 0 then
        return true, 2, skinRefId
    else
        return true, 1, skinRefId
    end
end

function ModelHero:ActiveOrWearSkin(skinRefId)
    local ref = self:GetShowEffectById(skinRefId)
    local heroRefId = ref.heroType

    local heroId = nil
    local maxPower = nil
    local heroList = self:GetHeroList()
    for k, v in pairs(heroList) do
        local refId = v:GetRefId()
        local power = v:GetPower()
        if refId == heroRefId then
            if not heroId or power > maxPower then
                heroId = v:GetId()
                maxPower = power
            end
        end
    end

    if heroId then
        gModelGeneral:OpenHeroSkin({ refId = heroRefId, id = heroId, gotoSkin = skinRefId })
    else
        gModelGeneral:OpenHeroSkin({ refId = heroRefId, skinRefId = skinRefId, preview = true })
        GF.ShowMessage(ccClientText(17420))--17420 您暂未获得该英雄无法激活使用皮肤
    end
end

