function ModelHero:GetBaseAttrInfoById(id, grade)
    local heroData = self:GetHeroStructById(id)
    local refId = heroData:GetRefId()
    local heroRef = self:GetHeroRef(refId)
    local classType = heroRef.classType
    grade = grade or heroData:GetGrade()
