function ModelHero:FilterHeroList(tCareer, tRace)
    local record = gModelFormation:GetOnFormationHeros(LCombatTypeConst.COMBAT_MAIN)
    local heroList = self:GetHeroSortList(record, nil, true)

    local combatHeroList = gModelFormation:GetHeroFormationData(LCombatTypeConst.COMBAT_MAIN)
    local allListData = {}
    local combatHero = {}
    local combatHeroRef = {}

    if heroList then
        for k, v in ipairs(heroList) do
            local refId = v:GetRefId()
            local id = v:GetId()
            local ref = gModelHero:GetHeroRef(refId)
            local bAdd = false

            if ref then
                local race = ref.raceType
                local career = ref.careerType
                bAdd = (tCareer == 0 or career == tCareer) and (tRace == 0 or race == tRace)
            end

            if combatHeroList[id] then
                bAdd = false
                local hero = v:GetServerData()
                table.insert(combatHero, hero)
                table.insert(combatHeroRef, ref)
            end

            if bAdd then
                local hero = v:GetServerData()
                table.insert(allListData, hero)
            end
        end
    end

    table.sort(combatHero, function(a, b)
        return a.fightPower < b.fightPower
    end)

    for k, v in ipairs(combatHero) do
        local refId = v.refId
        local ref = gModelHero:GetHeroRef(refId)

        local race = ref.raceType
        local career = ref.careerType
        local bAdd = false

        bAdd = (tCareer == 0 or career == tCareer) and (tRace == 0 or race == tRace)

        if bAdd then
            table.insert(allListData, 1, v)
        end
    end

    return allListData
end

function ModelHero:FilterAwakenHeroList(career, race)
    local heroList = self:FilterHeroList(career, race)
    local heroAwaken = self:GeConfigByKey("heroAwaken")
    local list = {}
    for k, v in ipairs(heroList) do
        local curStar = v.star
        if curStar >= heroAwaken then
            table.insert(list, v)
        end
    end

    return list
end

