function ModelHero:GetTotalLoveAttrs(totalLoveLv, isLvAttr)
    if not totalLoveLv then
        totalLoveLv = self._loveTotalLevel
    end
    if totalLoveLv == 0 then
        local ref = GameTable.CharacterFavorabilityAttrRef[1]
        local list = LxDataHelper.ParseAttrList(ref.attr)
        for _, attr in ipairs(list) do
            attr.value = 0
        end
        return list
    else
        local refs = GameTable.CharacterFavorabilityAttrRef
        local attrs = ""
        for _, value in pairs(refs) do
            if totalLoveLv >= value.refId and value.attr ~= "" then
                attrs = attrs .. "," .. value.attr
            end
            if isLvAttr and totalLoveLv >= value.refId and value.lvAttr ~= "" then
                attrs = attrs .. "," .. value.lvAttr
            end
        end
        local list = LxDataHelper.ParseAttrList(attrs)
        local attrMaps = {}
        for _, value in pairs(list) do
            if value and attrMaps[value.refId .. "-" .. value.type] then
                attrMaps[value.refId .. "-" .. value.type].value = attrMaps[value.refId .. "-" .. value.type].value + value.value
            elseif value.value then
                attrMaps[value.refId .. "-" .. value.type] = value
            end
        end
        local attrList = {}
        for _, value in pairs(attrMaps) do
            table.insert(attrList, value)
        end
        return attrList
    end
end
function ModelHero:IsActiveHeroEffRefId(heroEffId)
