function ModelHero:GetHeroEffectListByRefId(refId, isExistActive)
    --获取英雄的表现列表
    if not self._heroEffectRef then
        self._heroEffectRef = {}
        local heroEffRef = GameTable.CharacterEffectRef
        for _, value in pairs(heroEffRef) do
            if value.interactShow ~= 1 then
                if not self._heroEffectRef[value.heroType] then
                    self._heroEffectRef[value.heroType] = {}
                end
                table.insert(self._heroEffectRef[value.heroType], value)
            end
        end
    end
    local heroEffects = self._heroEffectRef[refId]
    local hasActive = false
    if isExistActive and heroEffects then
        for _, heroEff in ipairs(heroEffects) do
            if self:IsActiveHeroEffRefId(heroEff.refId) then
                hasActive = true
                break
            end
        end
    end
    return heroEffects, hasActive
end

