function ModelHero:GetHeroClickSound(heroEffRefId)
    local sound, soundStr = nil
    local heroEffRef = GameTable.CharacterEffectRef[heroEffRefId]
    local heroRefId = heroEffRef.heroType
    local loveLevel = self:GetHeroLoveLvByRefId(heroRefId)
    local favorRef = self:GetHeroSpActionSoundRef().heroClickSpActionSound
    if (loveLevel or 0) >= favorRef.refId then
        local sounds = string.split(heroEffRef[favorRef.SpActionSound] or "", ";")
        local desc = string.split(ccLngText(heroEffRef.heroClickSpActionDesc) or "", ";")
        local index = math.random(1, #sounds)
        sound = sounds[index]
        soundStr = desc[index] or desc[1]
    end
    return sound, soundStr
end

function ModelHero:GetFavorabilityGiftRed(heroRefId)

    if GameTable.CharacterRef[heroRefId].maxFavorability <= 0 then
        return false
    end
    local curLv = gModelHero:GetHeroLoveLvByRefId(heroRefId) or 0
    if not self:IsActiveHeroEffRefId(heroRefId) then
        return false
    end
    local nexLoveRef = GameTable.CharacterFavorabilityRef[curLv + 1]
    if not nexLoveRef then
        return false
    end
    local curExp = gModelHero:GetHeroLoveExpByRefId(heroRefId) or 0
    local needExp = nexLoveRef.exp - curExp
    local costStr = GameTable.CharacterRef[heroRefId].favorabilityGIft
    local costItem = string.split(costStr, ",")
    local usableLove = 0
    for i, v in ipairs(costItem) do
        local itemRef = GameTable.PlayerItemRef[tonumber(v)]
        local loves = string.split(itemRef.typeDate, ",")
        local itemLove = loves and tonumber(loves[1]) or 0
        local haveCount = gModelItem:GetNumByRefId(tonumber(v))
        usableLove = usableLove + itemLove * haveCount
        if usableLove > 0 and usableLove >= needExp then
            return true
        end
    end
    return false
end

function ModelHero:GetFavorabilityInteractRed(refId, interact)
    local heroEffectRef = GameTable.CharacterEffectRef[refId]
    local heroRefId = heroEffectRef.heroType
    local interactShow = heroEffectRef.interactShow
    local heroEffects, hasActive = self:GetHeroEffectListByRefId(heroRefId, true)
    if not heroRefId or interactShow == 1 or GameTable.CharacterRef[heroRefId].maxFavorability <= 0 or not heroEffects or not hasActive then
        return false
    end
    local loveInfo = self.favorabilityInfo[heroRefId]
    if not loveInfo or not loveInfo.interactionList then
        return false
    end
    local loveLevel = loveInfo.loveLevel or 0
    local refs = self:GetHeroSpActionSoundRef()
    local active = self:IsActiveHeroEffRefId(refId)
    if interact then
        local interactRef = refs.heroPlayItemSpAction
        local isOk = not loveInfo.interactionList[refId] or loveInfo.interactionList[refId] ~= 1 and loveInfo.interactionList[refId] ~= 3
        if isOk and interactRef.refId <= loveLevel and active then
            return true
        end
    else
        local closeUpRef = refs.heroCloseUpSpAction
        local isOk = not loveInfo.interactionList[refId] or loveInfo.interactionList[refId] ~= 2 and loveInfo.interactionList[refId] ~= 3
        if isOk and closeUpRef.refId <= loveLevel and active then
            return true
        end
    end
    return false
end

function ModelHero:IsOpenInteractCloseUp(heroEffRefId)
    local ref = GameTable.CharacterEffectRef[heroEffRefId]
    local refId = ref.heroType
    local isInteract, hasActive = gModelHero:GetHeroEffectListByRefId(ref.heroType, true)
    if not refId or string.isempty(ref.heroCloseUpSpAction) or not isInteract or not hasActive then
        return false
    end
    local active = self:IsActiveHeroEffRefId(heroEffRefId)
    if not active then
        return
    end
    local curLoveLv = self:GetHeroLoveLvByRefId(refId)
    local refs = self:GetHeroSpActionSoundRef()
    local closeUpRef = refs.heroCloseUpSpAction
    local tempRefId = closeUpRef and closeUpRef.refId

    if nil == tempRefId or nil == curLoveLv then
        printInfoN2("ModelHero", "拿不到配置--refs--refId" .. refId)
        return false
    end
    return tempRefId <= curLoveLv
end

