function ModelHero:GetHeroSuitState(heroId, equipRefId)
    local heroAttrList, equipList = self:GetHeroAttrAndEquipInfoById(heroId)

    local checkEquipRef = gModelEquip:GetEquipRefByRefId(equipRefId)

    if table.isempty(equipList) then
        equipList = {}
    end

    local checkSuitList = checkEquipRef.suitList

    --equipState 品质 -- 星级
    local equipState = {}

    for k, v in pairs(equipList) do
        --判断一次套装的类型
        local tempEquipRefId = v:GetRefId()
        local tempCheckEquipRef = gModelEquip:GetEquipRefByRefId(tempEquipRefId)
        local tempSuitList = tempCheckEquipRef.suitList
        local quality = tempCheckEquipRef.quality
        local star = tempCheckEquipRef.star

        if checkSuitList == tempSuitList then
            for i = quality, 0, -1 do
                if equipState[i] == nil then
                    equipState[i] = {}
                end
                for k = star, 0, -1 do
                    if equipState[i][k] == nil then
                        equipState[i][k] = 0
                    end
                    equipState[i][k] = equipState[i][k] + 1
                end
            end
        end
    end

    return equipState
end

--属性的套装效果是覆盖的关系
function ModelHero:GetHeroSuitAttrState(heroId, equipRefId)
    local heroAttrList, equipList = self:GetHeroAttrAndEquipInfoById(heroId)

    local suitList, tempSuitList, equipState = {}, {}, {}
    local addSuitList = {
        [1] = 0,
        [2] = 0,
        [3] = 0,
    }

    local addSuitListState = {
        [1] = false,
        [2] = false,
        [3] = false,
    }
    for k, v in pairs(equipList) do
        local wearEquipRef = gModelEquip:GetEquipRefByRefId(v:GetRefId())
        local tempSuit = wearEquipRef.suitList
        if tempSuit ~= 0 then
            local temp = tempSuit
            local tempInfo = tempSuitList[temp]
            if not tempInfo then
                tempSuitList[temp] = 1
            else
                tempSuitList[temp] = tempInfo + 1
            end
        end
        local quality = wearEquipRef.quality
        local star = wearEquipRef.star
        for i = quality, 1, -1 do
            if equipState[i] == nil then
                equipState[i] = {}
            end
            local tempStar = i >= quality and star or 5

            for k = tempStar, 1, -1 do
                if equipState[i][k] == nil then
                    equipState[i][k] = 0
                end
                equipState[i][k] = equipState[i][k] + 1
            end
        end
    end

    for k, v in pairs(tempSuitList) do
        table.insert(suitList, k)
    end

    table.sort(suitList, function(a, b)
        return a > b
    end)

    --记录完了   从大到小遍历
    for k, v in ipairs(suitList) do
        local refs = gModelEquip:GetSuitListBySuit(v)

        --遍历激活状态
        for i, j in ipairs(refs) do
            if not addSuitListState[j.suitLv] then
                local activationList = j.activationNum
                local temp = string.split(activationList, ",")
                local quality, starNum, activationNum = tonumber(temp[1]), tonumber(temp[2]), tonumber(temp[3])

                local activation = false
                if equipState[quality] then
                    if equipState[quality][starNum] and equipState[quality][starNum] >= activationNum then
                        activation = true
                    end
                end

                if activation then
                    addSuitList[j.suitLv] = j
                    addSuitListState[j.suitLv] = true
                end
            end
        end
    end

    for k, v in ipairs(addSuitListState) do
        if not v then
            --存在未激活的
            local checkEquipRef = gModelEquip:GetEquipRefByRefId(equipRefId)
            local checkSuitList = checkEquipRef.suitList
            local refs = gModelEquip:GetSuitListBySuit(checkSuitList)

            addSuitList[k] = refs[k]
        end
    end

    return addSuitList
end

