function ModelHero:GetHeroActShowState(heroRefId, curTime)
    local isOpen = true
    if not heroRefId then
        return isOpen
    end
    ---@type V_CharacterRef
    local ref = self:GetHeroRef(heroRefId)
    if ref then
        curTime = curTime or GetTimestamp()
        local isDmm = gLSdkImpl:CallMethod(LSdkMethod.IsDMMPlatform)
        local checkActShow
        if isDmm then
            if not string.isempty(ref.actShowDmm) then
                checkActShow = checknumber(ref.actShowDmm)
            end
        else
            if not string.isempty(ref.actShow) then
                checkActShow = checknumber(ref.actShow)
            end
        end
        if checkActShow and checkActShow > 0 then
            isOpen = checkActShow <= curTime
        end
    end
    return isOpen
end

function ModelHero:GetHeroUpLvLastNode(classType)
    if not self._heroUpLvLastNode then
        self._heroUpLvLastNode = {}
        local heroUpLvLastNode = gModelHero:GeConfigByKey("heroUpLvLastNode")

        local tempValue_1 = string.split(heroUpLvLastNode, "|")

        for k, v in ipairs(tempValue_1 or {}) do

            local tempValue_2 = string.split(v, "=")

            if tempValue_2 and tempValue_2[1] and tempValue_2[2] then

                self._heroUpLvLastNode[checknumber(tempValue_2[1])] = checknumber(tempValue_2[2])
            end
        end
    end

    return self._heroUpLvLastNode[classType] or 0
end

function ModelHero:GetNewHeroSortList(career, race)
    local formationHeroMap = gModelFormation:GetHeroFormationData(LCombatTypeConst.COMBAT_MAIN)
    local heroList = self:GetHeroList() or {}
    local normalHeroList = {}
    local combatHeroList = {}
    for k, v in pairs(heroList) do
        local refId = v:GetRefId()
        local ref = self:GetHeroRef(refId)
        if ref then
            local bAdd = false
            if career == 0 or career == ref.careerType then
                if race == 0 or race == ref.raceType then
                    bAdd = true
                end
            end
            if bAdd then
                if formationHeroMap[k] then
                    table.insert(combatHeroList, v:GetServerData())
                else
                    table.insert(normalHeroList, v:GetServerData())
                end
            end
        end
    end

    --- 2025/1/2 修改
    --- 出战的>非出战
    --- 高星级>高品质>战力高低>refID倒叙
    local sortFunc = function(a, b)
        local starA, starB = a.star, b.star
        if starA ~= starB then
            return starA > starB
        end
        local qualityA = self:GetHeroInitQualityByRefId(a.refId)
        local qualityB = self:GetHeroInitQualityByRefId(b.refId)
        if qualityA ~= qualityB then
            return qualityA > qualityB
        end
        local fightPowerA, fightPowerB = a.fightPower, b.fightPower
        if fightPowerA ~= fightPowerB then
            return fightPowerA > fightPowerB
        end
        return a.refId > b.refId
    end

    local list = {}
    if #combatHeroList > 0 then
        table.sort(combatHeroList, sortFunc)
        for i, v in ipairs(combatHeroList) do
            table.insert(list, v)
        end
    end
    if #normalHeroList > 0 then
        table.sort(normalHeroList, sortFunc)
        for i, v in ipairs(normalHeroList) do
            table.insert(list, v)
        end
    end
    return {
        sortHeros = list,
        formationHeroMap = formationHeroMap,
    }
end

function ModelHero:CheckNeedTranslateResType()
    if not gLGameLanguage:IsChinaRegion() then return end
    
    local isBlack = gLSdkImpl and gLSdkImpl:CallMethod(LSdkMethod.IsBlacklist)
    if isBlack then return end
    
    local needCheckNum = self:GetNeedCheckResTypeNum()
    if not needCheckNum or needCheckNum == -1 then
        --LogWarn("-----资源类型检测 获取不到升星对应数据")
        return 
    end
    
    local needCheckRes = false
    local bookInfoList = gModelHeroBook:GetBookInfoList()
    if bookInfoList then
        for heroRefId,info in pairs(bookInfoList) do
            if info.heroMaxStar >= needCheckNum then
                needCheckRes = true
                break
            end
        end
    end
    if not needCheckRes then return end
    LPlayerPrefs.GMSetLocalization(1)
end

function ModelHero:GetNeedCheckResTypeNum()
    local initNeedCheckResTypeMap = self._initNeedCheckResTypeMap
    if not initNeedCheckResTypeMap then
        initNeedCheckResTypeMap = {}
        local openTypeStr
        if CS.IsWebGL() and LWxHelper.IsMiniGamePlatform() then
            openTypeStr = GameTable.InnerActivityConfigRef["openStarsLevelWx"]
        else
            openTypeStr = GameTable.InnerActivityConfigRef["openStarsLevel"]
        end
        if not string.isempty(openTypeStr) then
            local openTypeStrs = string.split(openTypeStr,"|")
            for i,v in ipairs(openTypeStrs) do
                v = string.split(v,"=")
                initNeedCheckResTypeMap[checknumber(v[1])] = checknumber(v[2])
            end
        end
        self._initNeedCheckResTypeMap = initNeedCheckResTypeMap
    end
    local resType = LPlayerPrefs.GetLocalization()
    return resType and initNeedCheckResTypeMap[resType]
end

return ModelHero